import type { Drill } from "./types";

// Public service / senior drills, keyed by module slug — 25 per module.
// Department director / chief / senior government official: briefing councils and
// legislators, defending budgets, facing the press, leading through crises. Merged into course.ts.
export const PUBLICSERVICE_SENIOR_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-gov-senior-01","level":"senior","profession":"publicservice","title":"The buried recommendation","scenario":"Your briefing memo to council on the transit contract runs three pages of procurement history before the recommendation appears. Councilmembers read the first paragraph and skim the rest.","task":"Write the opening 2-3 sentences of the memo, recommendation first.","tips":["Sentence one: what you recommend council approve and the dollar figure.","Procurement history is backup, not the opening.","A councilmember should be able to vote from paragraph one."],"focus":["structure","clarity"],"placeholder":"Recommendation: approve the $2.1M, two-year extension of the transit maintenance contract."},
    {"id":"lead-gov-senior-02","level":"senior","profession":"publicservice","title":"The storm update the mayor skims","scenario":"It's 6 a.m. after an ice storm. The mayor wants your department's status before her 7 a.m. media availability. Your draft opens with a chronology of the overnight response instead of where things stand now.","task":"Write a 2-3 sentence status update that leads with current state.","tips":["First line: what is open, what is closed, who is affected right now.","The overnight timeline is background — put it after or cut it.","Give the mayor the sentence she can say on camera."],"focus":["clarity","impact"],"placeholder":"All arterial routes are clear; 14 residential zones remain iced, expected clear by noon."},
    {"id":"lead-gov-senior-03","level":"senior","profession":"publicservice","title":"The budget ask that hides its number","scenario":"You are requesting $3.4M in the next fiscal year to replace the department's radio system. Your draft to the finance committee spends two paragraphs on the system's history before naming the amount.","task":"Write an opening that states the ask and the reason in the first two sentences.","tips":["Lead with the number and what it buys.","One sentence on why now — failure risk, end of vendor support.","Justification detail belongs in the body, not the opening."],"focus":["structure","impact"],"placeholder":"I am requesting $3.4M in FY28 to replace the radio system that reaches end of vendor support in March."},
    {"id":"lead-gov-senior-04","level":"senior","profession":"publicservice","title":"The press statement that buries the break","scenario":"A water main failure has cut service to 3,000 homes. Your communications draft opens with the department's commitment to infrastructure before saying what happened, who is affected, and when service returns.","task":"Write the first 2 sentences of the public statement: what happened, who is affected, when it will be fixed.","tips":["Residents scan for three things: what, am I affected, when is it fixed.","Institutional throat-clearing erodes trust in a crisis.","Commit to a next update time if the fix time is unknown."],"focus":["clarity","audience"]},
    {"id":"lead-gov-senior-05","level":"senior","profession":"publicservice","title":"The audit finding email","scenario":"The auditor general found that your department overpaid a vendor by $180K over two years. You must inform the city manager today. Your draft eases in with context about the contract before naming the finding.","task":"Write a 3-sentence email that states the finding first, then the fix underway.","tips":["Lead with the finding and the number — the city manager will hear it anyway.","Sentence two: what you are already doing about it.","Burying bad news reads as spin when it surfaces later."],"focus":["clarity","impact"],"placeholder":"The audit found we overpaid Ridgeline Services $180K over two years due to a duplicate billing code."},
    {"id":"lead-gov-senior-06","level":"senior","profession":"publicservice","title":"The bill position in one breath","scenario":"The legislative liaison calls: a committee votes on Bill 214 in two hours and needs your department's position now. You start explaining the bill's five sections before saying whether you support it.","task":"State your position and the single biggest reason in 2 sentences.","tips":["Position first: support, oppose, or support with amendment.","One reason the liaison can repeat verbatim in the committee room.","Section-by-section analysis can follow in writing."],"focus":["clarity","concision"],"placeholder":"We oppose Bill 214 as written —"},
    {"id":"lead-gov-senior-07","level":"senior","profession":"publicservice","title":"The weekly report that hides the milestone","scenario":"Your weekly report to the county executive covers routine operations, but the real news is that the new permitting portal went live and cut average processing from 21 days to 6. That sits in bullet seven.","task":"Write the opening line of the report that leads with the result.","tips":["Lead with the outcome and the numbers, not the list of activities.","Routine operations can be a short section below.","If the executive reads one line, make it the win."],"focus":["structure","impact"],"placeholder":"The permitting portal is live: average processing time dropped from 21 days to 6 in week one."},
    {"id":"lead-gov-senior-08","level":"senior","profession":"publicservice","title":"The shortfall you have to name","scenario":"The summer youth employment program will serve 400 fewer teens than council announced, because a federal grant came in short. Your draft to the CAO explains grant mechanics for a page before stating the gap.","task":"Write a 2-3 sentence escalation that leads with the shortfall and its cause.","tips":["First sentence: the gap in plain numbers — 400 fewer placements.","Attribute the cause in one clause, without defensiveness.","End with the decision you need or the option you propose."],"focus":["clarity","impact"]},
    {"id":"lead-gov-senior-09","level":"senior","profession":"publicservice","title":"The ask to a peer director","scenario":"You need two of Public Works' inspectors for three weeks to clear a permit backlog before the council's deadline. Your draft email to their director recounts the backlog's history before making the request.","task":"Write an email that puts the specific ask — who, how long, by when — in the first sentence.","tips":["Lead with the request: two inspectors, three weeks, starting Monday.","One sentence on the stake: the council deadline.","Make it easy to say yes — offer the reciprocal favor or backfill plan."],"focus":["clarity","concision"],"placeholder":"Could I borrow two of your building inspectors for three weeks starting Monday?"},
    {"id":"lead-gov-senior-10","level":"senior","profession":"publicservice","title":"The bargaining update for the executive team","scenario":"After the fourth negotiation session with the union, the executive team wants to know where things stand. Your draft narrates each session in order; the headline — agreement on wages, deadlock on scheduling — comes last.","task":"Write a 2-sentence update that leads with where the deal stands.","tips":["First sentence: what is settled and what is stuck.","Session-by-session narrative is an appendix, not the update.","Name what you need from the executive team, if anything."],"focus":["structure","concision"],"placeholder":"We have tentative agreement on wages; scheduling language is deadlocked."},
    {"id":"lead-gov-senior-11","level":"senior","profession":"publicservice","title":"The agenda cover memo","scenario":"Your item is twelfth on tonight's council agenda. The cover memo is councilmembers' only preparation, and your current draft opens with statutory background instead of what you are asking them to do.","task":"Write a cover memo opening that states the requested action in sentence one.","tips":["Sentence one: the action requested and the cost, if any.","Statutory authority is a citation, not a lead.","Assume the member reads it on the dais, sixty seconds before the vote."],"focus":["clarity","structure"]},
    {"id":"lead-gov-senior-12","level":"senior","profession":"publicservice","title":"The grant deadline heads-up","scenario":"A federal infrastructure grant worth up to $12M closes in three weeks, and applying requires a council resolution at next week's meeting. Your note to the mayor's chief of staff starts by describing the grant program's goals.","task":"Write a 2-sentence heads-up that leads with the deadline and the required action.","tips":["Lead with what must happen and by when: resolution next week, application in three weeks.","The dollar figure earns the urgency — put it in sentence one.","Program description can wait for the briefing."],"focus":["clarity","impact"],"placeholder":"We need a council resolution next Tuesday to apply for a federal grant worth up to $12M — the window closes in three weeks."},
    {"id":"lead-gov-senior-13","level":"senior","profession":"publicservice","title":"The overnight ops email to council","scenario":"Councilmembers wake up to constituent calls about the overnight shelter that reached capacity and turned people away in the cold. Your 7 a.m. email to all members opens with a description of the shelter system before addressing what happened.","task":"Write the first 2 sentences: what happened, and what you are doing about it today.","tips":["Members need the facts before their first constituent call — lead with them.","Say what changes today, not just what went wrong.","Anticipate the question they will be asked and answer it up front."],"focus":["clarity","audience"]},
    {"id":"lead-gov-senior-14","level":"senior","profession":"publicservice","title":"The records request risk","scenario":"A journalist's records request will surface emails showing your department knew about a facility problem months before acting. You need the city attorney's guidance before the statutory release date Friday. Your draft buries that ask under a full narrative.","task":"Write a 2-3 sentence message that leads with what you need from counsel and by when.","tips":["Lead with the ask: guidance before Friday's release deadline.","One sentence on why: what the records will show.","Counsel needs the deadline first — the narrative can come in the meeting."],"focus":["clarity","precision"],"placeholder":"I need your guidance before Friday, when we must release records showing"},
    {"id":"lead-gov-senior-15","level":"senior","profession":"publicservice","title":"The contract award memo","scenario":"After a six-month procurement, you are recommending the second-lowest bidder because the lowest failed the technical evaluation. Your award memo walks through the entire process chronologically before naming the winner.","task":"Write an opening that names the recommended vendor and the key reason in 2 sentences.","tips":["Lead with the recommendation and price.","Immediately address the obvious question: why not the lowest bid?","Process chronology proves diligence — in the body, not the lead."],"focus":["structure","clarity"]},
    {"id":"lead-gov-senior-16","level":"senior","profession":"publicservice","title":"The options memo with a hidden pick","scenario":"The deputy minister asked for options on consolidating the two licensing offices. You have a clear view — consolidate into the north office — but your draft presents three options neutrally and saves your judgment for the final line.","task":"Rewrite the opening so your recommended option leads, with the alternatives following.","tips":["State your recommendation in sentence one, then present the alternatives fairly.","Officials asked you because you know the operation — give them your judgment.","Neutral menus push the decision back up without adding value."],"focus":["clarity","impact"],"placeholder":"I recommend Option B — consolidating into the north office —"},
    {"id":"lead-gov-senior-17","level":"senior","profession":"publicservice","title":"The testimony opener","scenario":"You have five minutes before the legislative committee on the proposed staffing mandate. Your drafted opening thanks the chair, describes your department, and reaches your actual position at minute two.","task":"Write an opening 2 sentences that state your position immediately after the greeting.","tips":["One clause of courtesy, then the position.","Committee members decide in the first thirty seconds whether to listen.","Every sentence before your point is a sentence they spend on their phones."],"focus":["clarity","impact"]},
    {"id":"lead-gov-senior-18","level":"senior","profession":"publicservice","title":"The call-center surge alert","scenario":"Calls to your benefits line tripled this morning after a confusing renewal notice went out. Wait times are over an hour. Your alert to the executive team describes the notice's mailing history before stating the operational impact.","task":"Write a 2-sentence alert that leads with the impact and the immediate fix.","tips":["First sentence: what is happening to residents right now.","Second: what you are doing in the next few hours.","Root cause gets one clause, not a paragraph."],"focus":["clarity","impact"],"placeholder":"Benefits-line wait times are over an hour after this morning's renewal notice confused recipients."},
    {"id":"lead-gov-senior-19","level":"senior","profession":"publicservice","title":"The media inquiry alert","scenario":"A television reporter has asked for comment on overtime spending in your department, with a 4 p.m. deadline. Your internal alert to the communications director and CAO opens with a defense of the overtime before stating what was asked and when.","task":"Write a 2-sentence internal alert: the inquiry, the deadline, and your proposed response posture.","tips":["Lead with what was asked and the deadline — that drives everyone's next hour.","Your proposed posture (respond, decline, background) is the decision on the table.","Save the substantive defense for the response itself."],"focus":["concision","structure"]},
    {"id":"lead-gov-senior-20","level":"senior","profession":"publicservice","title":"The modernization slip","scenario":"The case-management system replacement council approved will go live in October, not June, after the data migration failed testing. Your memo to the technology committee explains migration architecture before revealing the new date.","task":"Write a 2-3 sentence opening that leads with the new date and the cost impact.","tips":["The new date is the news — sentence one.","State the cost impact or confirm there is none.","Technical explanation earns one plain-language sentence, not a page."],"focus":["clarity","precision"],"placeholder":"The case-management go-live moves from June to October; the budget does not change."},
    {"id":"lead-gov-senior-21","level":"senior","profession":"publicservice","title":"The public meeting opener","scenario":"Two hundred residents are at the community meeting about the proposed fire station relocation. Your prepared opening covers the department's history in the neighborhood before stating what decision is actually on the table tonight.","task":"Write an opening 2 sentences that tell residents exactly what is being decided and what input you need.","tips":["Name the decision and the timeline before anything else.","Tell residents what their input can and cannot change — honestly.","History and warmth can follow; clarity buys you the room's patience."],"focus":["clarity","audience"]},
    {"id":"lead-gov-senior-22","level":"senior","profession":"publicservice","title":"The constituent fix, reported back","scenario":"A councilmember escalated a constituent's six-month benefits delay to you personally. It is fixed — payment issued yesterday, plus back pay. Your reply to the member opens with an explanation of the eligibility system's complexity.","task":"Write a 2-sentence reply that leads with the resolution.","tips":["First sentence: it is fixed, payment issued, back pay included.","The member forwards your first line to the constituent — write it for that.","System complexity reads as excuse after good news, and worse before it."],"focus":["clarity","audience"],"placeholder":"Resolved: Ms. Okafor's payment was issued yesterday, including full back pay to January."},
    {"id":"lead-gov-senior-23","level":"senior","profession":"publicservice","title":"The cross-department kickoff","scenario":"You are launching a joint effort with Health and Housing to cut chronic-homelessness casework duplication. Your kickoff email to the three teams describes each department's mandate before stating the shared goal and first deliverable.","task":"Write an opening that states the goal, the first deliverable, and the deadline in 2-3 sentences.","tips":["Lead with the one shared goal in plain words.","Name the first concrete deliverable and its date.","Mandate descriptions are why people tune out — cut them."],"focus":["structure","impact"]},
    {"id":"lead-gov-senior-24","level":"senior","profession":"publicservice","title":"The thirty-second brief","scenario":"You catch the deputy minister in the corridor. You have thirty seconds to tell her the inspection backlog is resolved and secure her agreement to reassign the temporary staff next month. You tend to start with how the backlog arose.","task":"Script your 2-sentence corridor brief: the news, then the ask.","tips":["News first: backlog cleared, three weeks early.","Ask second: approval to reassign the temps next month.","If she walks away after sentence one, she still has the headline."],"focus":["concision","impact"],"placeholder":"The inspection backlog is cleared, three weeks early —"},
    {"id":"lead-gov-senior-25","level":"senior","profession":"publicservice","title":"The all-staff after the outage","scenario":"The payroll system failure that delayed 400 employees' pay is fixed; deposits land tomorrow. Your all-staff draft opens with an account of the vendor's server failure before telling staff the one thing they care about.","task":"Write the first 2 sentences of the all-staff message.","tips":["Sentence one: your pay arrives tomorrow.","Sentence two: what you are doing so it does not repeat.","Staff scan for their own stake first — serve it first."],"focus":["clarity","audience"]}
  ],
  "start-with-the-audience": [
    {"id":"audience-gov-senior-01","level":"senior","profession":"publicservice","title":"The council with no operations background","scenario":"You are briefing council on why the wastewater plant needs a $40M upgrade. Your draft leans on terms like effluent limits, biosolids capacity, and consent-order thresholds. Most members have never toured the plant.","task":"Rewrite the core argument in 3-4 sentences a non-specialist councilmember can repeat to constituents.","tips":["Translate each technical term into consequence: fines, smells, moratorium on new housing.","The member's stake is defending the vote — arm them for that conversation.","Keep one number, the one that matters most."],"focus":["audience","clarity"],"placeholder":"Without this upgrade, the plant hits its legal capacity limit in 2029 — which means a freeze on new housing connections."},
    {"id":"audience-gov-senior-02","level":"senior","profession":"publicservice","title":"The press release nobody outside the building understands","scenario":"Your draft release announces that the department 'completed procurement of an interoperable CAD-to-CAD interface enhancing mutual-aid dispatch capability.' A resident reading the local paper should understand why this matters to them.","task":"Rewrite the announcement in 2-3 sentences of plain language centered on the resident's stake.","tips":["Lead with the outcome a resident feels: faster help when they call 911.","Every acronym must earn its place or be cut.","Test: would your neighbor understand it on first read?"],"focus":["audience","clarity"]},
    {"id":"audience-gov-senior-03","level":"senior","profession":"publicservice","title":"Same news, two rooms","scenario":"The state cut your department's grant by 15%. You must explain it this afternoon to the executive team, who need budget mechanics, and tomorrow to frontline staff, who want to know if their jobs are safe.","task":"Write the 2-sentence opening for the staff meeting — not the executive version.","tips":["Answer the staff's real question first: what this means for jobs.","Budget mechanics are the executive audience's need, not this one's.","Do not soften into vagueness — staff read vagueness as bad news hidden."],"focus":["audience","clarity"],"placeholder":"The state cut our grant by 15%. No layoffs — here is what changes instead."},
    {"id":"audience-gov-senior-04","level":"senior","profession":"publicservice","title":"The legislator's aide, not the legislator","scenario":"You have twenty minutes with a legislative aide who covers fourteen policy areas and will summarize your issue to the member in three sentences. Your team's briefing deck was built for subject-matter experts.","task":"Write the 3 sentences you want the aide to carry back to the member.","tips":["Write the aide's summary for them — that is what actually reaches the member.","One ask, one reason, one local impact in the member's district.","Depth is available on request; it is not the pitch."],"focus":["audience","concision"]},
    {"id":"audience-gov-senior-05","level":"senior","profession":"publicservice","title":"The rate increase letter","scenario":"Water rates are rising 9% to fund pipe replacement. The draft letter to households opens with the utility's capital financing structure. Residents will read two sentences before deciding whether this is fair or an outrage.","task":"Write the first 2-3 sentences of the letter to residents.","tips":["Lead with what changes for them: the dollar amount on a typical bill.","Give the reason in concrete terms — the age of the pipes, what fails without it.","Respect the reader's anger; do not talk past it with finance-speak."],"focus":["audience","clarity"],"placeholder":"Starting July 1, the average household water bill rises by $6.40 a month."},
    {"id":"audience-gov-senior-06","level":"senior","profession":"publicservice","title":"The curse of the org chart","scenario":"Your memo to the new mayor references 'the DRC process,' 'the 380 agreement,' and 'the interlocal with the county' — shorthand that took you a decade to absorb. The mayor took office nine days ago.","task":"Rewrite one paragraph of the memo assuming zero institutional memory.","tips":["Spell out every acronym and name what each agreement actually does.","One sentence of context per term — not a history lesson.","The goal is a mayor who can act, not one who must schedule a follow-up."],"focus":["audience","clarity"]},
    {"id":"audience-gov-senior-07","level":"senior","profession":"publicservice","title":"The auditor's altitude","scenario":"The audit committee asked why permit revenue fell 12%. Your program manager drafted four pages on seasonal application patterns and fee-code recategorization. The committee wants to know one thing: is this a problem, and is it managed?","task":"Write a 3-sentence answer at the committee's altitude.","tips":["Answer the governance question: is this a risk, and who is on it?","One driver, one number, one action — not four pages of pattern analysis.","Offer the detail as an attachment, not the answer."],"focus":["audience","structure"],"placeholder":"The 12% drop is explained by a fee-code change, not lost activity —"},
    {"id":"audience-gov-senior-08","level":"senior","profession":"publicservice","title":"The eligibility rules, twice","scenario":"New childcare-subsidy eligibility rules take effect Monday. You must brief caseworkers, who need decision rules, and write the public notice for applicants, who need to know if they qualify. Your team drafted one document for both.","task":"Write the 2-sentence public version for applicants.","tips":["Applicants ask one question: do I qualify and how do I apply?","Decision-rule logic belongs in the caseworker version only.","Use the reader's words — income, family size — not program terms."],"focus":["audience","clarity"]},
    {"id":"audience-gov-senior-09","level":"senior","profession":"publicservice","title":"The neighborhood association and the crime stats","scenario":"You are presenting public-safety data to a neighborhood association alarmed by a burglary spree. Your analyst's slides show year-over-year percentage changes by UCR category. The room wants to know if their street is safe and what you are doing.","task":"Write the 2-3 sentence opening of your remarks.","tips":["Speak to the fear first — name the spree, say what is being done this week.","Pick the one statistic that speaks to their experience, translated.","Percentage tables persuade analysts, not worried neighbors."],"focus":["audience","impact"]},
    {"id":"audience-gov-senior-10","level":"senior","profession":"publicservice","title":"The minister's one slide","scenario":"Your 30-slide program review must become one slide for the minister, who will decide whether the program survives. Your team's summary slide lists twelve bullet points of findings at equal weight.","task":"Write the 3 lines that belong on the minister's slide.","tips":["The minister's question is keep, fix, or kill — answer it.","One outcome number, one cost number, one recommendation.","Everything at equal weight means nothing has weight."],"focus":["audience","concision"],"placeholder":"Recommend: continue with restructuring. The program meets its outcome target"},
    {"id":"audience-gov-senior-11","level":"senior","profession":"publicservice","title":"The consent decree, explained to staff","scenario":"Your agency has entered a court-ordered consent decree on service timeliness. Staff are hearing 'federal monitor' and fearing the worst. Your all-staff message must explain what the decree actually changes about their daily work.","task":"Write a 3-4 sentence explanation for frontline staff.","tips":["Translate the legal instrument into daily-work terms: what is measured, what changes.","Address the unspoken fear directly — is this about blaming staff?","Keep the legal framing for the lawyers; staff need the operational truth."],"focus":["audience","clarity"]},
    {"id":"audience-gov-senior-12","level":"senior","profession":"publicservice","title":"The radio interview translation","scenario":"You are on drive-time radio tomorrow about the landfill closure decision. Your briefing note says the site 'reaches airspace capacity in Q3 2028.' Listeners are half-attentive commuters who need the point in one pass.","task":"Write the one plain-language sentence you will use on air, then a follow-up sentence on what happens next.","tips":["No jargon survives radio — 'airspace capacity' becomes 'the landfill will be full.'","One sentence, one idea; listeners cannot re-read.","Follow with the reassurance question: what happens to my trash pickup?"],"focus":["audience","clarity"],"placeholder":"The landfill will be full by late 2028, so we have to decide now where the region's trash goes next."},
    {"id":"audience-gov-senior-13","level":"senior","profession":"publicservice","title":"The two-audience memo trap","scenario":"Your draft memo about the shelter policy change tries to serve council (who need the policy rationale) and shelter operators (who need operational instructions) in one document. It serves neither.","task":"Choose the primary audience and write the memo's 2-sentence opening for that audience alone.","tips":["Pick one primary reader; the other gets a separate, shorter document.","A memo for everyone is a memo for no one.","State your choice implicitly through what you lead with."],"focus":["audience","structure"]},
    {"id":"audience-gov-senior-14","level":"senior","profession":"publicservice","title":"The business owners and the new rule","scenario":"A new sidewalk-cafe permitting rule takes effect in 60 days. Your notice to affected restaurant owners is drafted in regulatory language — 'encroachment permits,' 'right-of-way clearances.' Owners need to know what to do by when, or they lose their patios.","task":"Rewrite the notice's opening 2-3 sentences in the owner's terms.","tips":["Lead with the action and deadline: apply by this date or the patio closes.","Translate each regulatory term into the thing the owner recognizes.","Put the help channel — who to call — in the opening, not the footer."],"focus":["audience","clarity"],"placeholder":"To keep your patio open past June 1, you need to submit the new sidewalk-cafe application by April 30."},
    {"id":"audience-gov-senior-15","level":"senior","profession":"publicservice","title":"The overdose data at the school board","scenario":"You are presenting youth overdose trends to the school board. Your health analysts framed the data epidemiologically — rates per 100,000, confidence intervals. Board members need to decide whether to fund school-based counselors.","task":"Write the 2-sentence framing that connects the data to the board's decision.","tips":["Frame the data around the decision in front of them, not the methodology.","Convert the rate into their unit: students in this district, this year.","The board's stake is their students and their budget — speak to both."],"focus":["audience","impact"]},
    {"id":"audience-gov-senior-16","level":"senior","profession":"publicservice","title":"The union hall, not the boardroom","scenario":"You are explaining the department's restructuring to the union membership meeting tonight. Your deck was built for the executive committee — 'span of control,' 'service-delivery model,' 'FTE realignment.' Members want to know: my job, my shift, my pay.","task":"Write the 3 sentences you will open with at the union hall.","tips":["Answer job security first, in words with no wiggle room.","'FTE realignment' means someone's shift changes — say whose and how.","Respect the room: they detect boardroom language instantly and distrust it."],"focus":["audience","clarity"]},
    {"id":"audience-gov-senior-17","level":"senior","profession":"publicservice","title":"The federal partner vs. the local one","scenario":"The same flood-mitigation project update goes to the federal funding agency, which needs compliance milestones, and to the neighborhood flood committee, which needs to know when the berm protects their homes. Your officer drafted one identical update for both.","task":"Write the 2-sentence version for the neighborhood committee.","tips":["The committee's question: when am I protected, and what happens this hurricane season?","Compliance milestones are the funder's language — cut them here.","Concrete dates and physical progress beat process status."],"focus":["audience","clarity"],"placeholder":"The berm will protect homes on the east bank by August — before peak storm season."},
    {"id":"audience-gov-senior-18","level":"senior","profession":"publicservice","title":"The incoming director's briefing book","scenario":"You are writing the transition brief for your successor, an experienced executive from another state who knows the field but not this jurisdiction. Your team's draft explains basics she already knows and skips the local landmines she does not.","task":"Write a 3-4 sentence 'what you actually need to know' opening.","tips":["Calibrate to her expertise: skip the field basics, name the local specifics.","Lead with the two things that will burn her in month one.","Institutional relationships and history are her real blind spots — map them."],"focus":["audience","precision"]},
    {"id":"audience-gov-senior-19","level":"senior","profession":"publicservice","title":"The grant funder's language","scenario":"Your program officer wrote the federal grant progress report in the department's internal vocabulary — unit names, local program acronyms. The federal reviewer scores against the grant's own outcome measures and has never heard of your units.","task":"Rewrite 2-3 sentences of the report mapped to the funder's outcome language.","tips":["Use the funder's own terms from the award document — they score by matching.","Translate your unit names into functions the reviewer recognizes.","Every claimed outcome should tie to a measure in the grant agreement."],"focus":["audience","precision"]},
    {"id":"audience-gov-senior-20","level":"senior","profession":"publicservice","title":"The town hall on a technical failure","scenario":"A software error caused 2,100 households to receive incorrect tax bills. At tonight's town hall you must explain what happened. Your IT chief's summary involves batch-processing sequences and rate-table versioning.","task":"Write the 2-3 sentence explanation you will give residents.","tips":["Residents need three things: what went wrong, is my bill right now, what do I do.","'A software error applied last year's rates' is enough cause — no batch jobs.","Give the verification step: how a resident checks their own bill."],"focus":["audience","clarity"],"placeholder":"A software error applied last year's tax rates to about 2,100 bills. Corrected bills mail Friday —"},
    {"id":"audience-gov-senior-21","level":"senior","profession":"publicservice","title":"The chief's blotter vs. the chief's briefing","scenario":"As public-safety director you brief both the police command staff, who need tactical specifics about the robbery pattern, and the business improvement district, who need reassurance and prevention steps. The same incident summary is going to both.","task":"Write the 2-sentence version for the business district.","tips":["Businesses need: the pattern in plain terms, prevention steps, and a contact.","Tactical detail helps command staff and helps the robbers — keep it internal.","Reassure with actions being taken, not adjectives."],"focus":["audience","impact"]},
    {"id":"audience-gov-senior-22","level":"senior","profession":"publicservice","title":"The dashboard the public sees","scenario":"Your open-data team built a public performance dashboard, and the pothole-repair metric reads 'SR closure rate: 87% within SLA.' Residents checking whether their street gets fixed do not know what an SR or an SLA is.","task":"Rewrite the metric label and its one-line explanation for a public audience.","tips":["Name the thing residents recognize: potholes reported, potholes fixed, how fast.","Internal terms — SR, SLA — mark the dashboard as not for the public.","One test: could a resident use it to know what to expect?"],"focus":["audience","clarity"],"placeholder":"87% of reported potholes are fixed within 5 business days."},
    {"id":"audience-gov-senior-23","level":"senior","profession":"publicservice","title":"The op-ed altitude check","scenario":"You are drafting an op-ed defending the regional transit expansion. Your first draft argues farebox recovery ratios and federal match formulas. Newspaper readers decide based on their commute, their taxes, and whether they trust the plan.","task":"Write the op-ed's opening 2-3 sentences at the reader's altitude.","tips":["Open with the reader's experience: the commute that takes an hour today.","Funding formulas persuade budget staff; time and cost persuade readers.","One number maximum in the opening, and make it a resident-scale number."],"focus":["audience","impact"]},
    {"id":"audience-gov-senior-24","level":"senior","profession":"publicservice","title":"The interdepartmental ask, translated","scenario":"You need the IT department to prioritize your inspection app fix. Your draft explains inspection workflows they have never seen. IT's world is tickets, severity levels, and competing directors demanding priority.","task":"Rewrite the ask in 2-3 sentences framed in IT's terms and decision criteria.","tips":["Frame in their currency: severity, user impact, and what slips if they say yes.","Explain your workflow only enough to justify the severity claim.","Acknowledge the queue — name what you would deprioritize or escalate honestly."],"focus":["audience","clarity"]},
    {"id":"audience-gov-senior-25","level":"senior","profession":"publicservice","title":"The eulogy for a program, two ways","scenario":"A beloved senior-center meal program ends when its grant expires. The notice to participants and the memo to the funding committee cannot be the same document — one audience is losing lunches with friends; the other needs the fiscal record.","task":"Write the 2-3 sentence notice for participants.","tips":["Lead with the human facts: the last date, and what replaces it for them.","Name the alternative arrangements before the explanation.","Warm, plain, and specific — participants deserve better than budget language."],"focus":["audience","clarity"],"placeholder":"The Tuesday lunch program at Fairview Senior Centre will end June 27."}
  ],
  "structure-that-carries": [
    {"id":"structure-gov-senior-01","level":"senior","profession":"publicservice","title":"The budget defense in three buckets","scenario":"Your budget hearing is Thursday. Your defense of the department's $84M request currently walks through all fourteen divisions line by line. The committee will retain none of it.","task":"State one governing message for the budget and the 3 buckets that carry it.","tips":["One sentence the committee should remember: what this budget buys the public.","Group fourteen divisions into three outcome buckets, not org-chart order.","Every line item should visibly belong to a bucket."],"focus":["structure","clarity"],"placeholder":"This budget does three things: keeps core services at current levels, replaces failing infrastructure, and"},
    {"id":"structure-gov-senior-02","level":"senior","profession":"publicservice","title":"SCQA for the policy memo","scenario":"You are recommending the province adopt a regional dispatch model. Your memo dives straight into the recommendation with no setup, and readers keep asking 'wait, what problem is this solving?'","task":"Write the memo's opening as SCQA: Situation, Complication, Question, Answer — one sentence each.","tips":["Situation: the stable fact everyone agrees on.","Complication: what changed or broke that demands action.","The Answer is your recommendation — SCQA earns it a hearing."],"focus":["structure","clarity"]},
    {"id":"structure-gov-senior-03","level":"senior","profession":"publicservice","title":"PREP for the hearing answer","scenario":"At Thursday's oversight hearing you will be asked whether the department can absorb a 5% cut without service reductions. You know the answer is no, but your practice answers wander through caveats and lose the point.","task":"Script a PREP answer — Point, Reason, Example, Point — in 4 sentences.","tips":["Point first: no, not without cutting services.","One reason with a number; one concrete example the members can picture.","Restate the point at the end — hearings reward closed loops."],"focus":["structure","clarity"],"placeholder":"No — a 5% cut means service reductions, and I want to be direct about that."},
    {"id":"structure-gov-senior-04","level":"senior","profession":"publicservice","title":"Grouping the audit findings","scenario":"The internal audit produced eleven findings about your permitting operation, listed in the order discovered: two about fee handling, four about documentation, three about turnaround times, two about training. Your response memo currently mirrors that random order.","task":"Group the findings into 3 named themes and write the sentence introducing them.","tips":["Group by root cause or theme, not by discovery order.","Name each group with a claim, not a topic — 'documentation gaps stem from one outdated manual.'","Three groups the committee can hold beats eleven items they cannot."],"focus":["structure","clarity"]},
    {"id":"structure-gov-senior-05","level":"senior","profession":"publicservice","title":"The council presentation skeleton","scenario":"You have ten minutes to present the homelessness strategy update to council. Your slides currently follow your team's workplan structure — outreach, shelter, housing, data — with no argument connecting them.","task":"Write the governing idea and the 3 supporting points, one sentence each.","tips":["A governing idea is a claim: 'the strategy is working where housing exists, and stalling where it does not.'","Each supporting point should independently support the claim.","Workplan categories describe your org; arguments move your audience."],"focus":["structure","impact"]},
    {"id":"structure-gov-senior-06","level":"senior","profession":"publicservice","title":"The transition book that has no spine","scenario":"The incoming administration takes office in six weeks. Your transition briefing book is 200 pages of division summaries with no organizing frame. The new deputy will read the first five pages carefully and skim the rest.","task":"Write the 3-part frame for the opening memo: what to protect, what to decide, what to watch.","tips":["Organize by the reader's job — decisions and risks — not by your org chart.","Rank within each part; the first item under 'decide' should be the most urgent.","One page of frame makes 200 pages of detail navigable."],"focus":["structure","audience"],"placeholder":"Three things need your attention in the first 90 days: one decision, one risk, and one commitment already in motion."},
    {"id":"structure-gov-senior-07","level":"senior","profession":"publicservice","title":"The reorg announcement that answers in order","scenario":"You are announcing a department restructuring that merges two divisions and creates a new deputy role. Your draft announcement presents the changes in the order the design team settled them, which is not the order staff care about them.","task":"Reorder the announcement into 3 sections matched to the reader's questions, and write the first sentence of each.","tips":["Staff triage: does my job change, who do I report to, why is this happening.","Structure follows the reader's questions, not the project's chronology.","Signpost the sections so a worried reader can jump to their answer."],"focus":["structure","audience"]},
    {"id":"structure-gov-senior-08","level":"senior","profession":"publicservice","title":"The grant narrative pyramid","scenario":"Your team's federal grant narrative for the violence-prevention program reads as a chronological program history. Reviewers score against three criteria: need, approach, and capacity — and they are skimming their fortieth application.","task":"Write the narrative's governing claim and map its 3 sections to the scoring criteria, one sentence each.","tips":["Lead with the claim that answers 'why fund this one': the need, met by this approach, by this team.","Mirror the reviewer's rubric in your headings — make scoring effortless.","History appears only where it proves capacity."],"focus":["structure","audience"]},
    {"id":"structure-gov-senior-09","level":"senior","profession":"publicservice","title":"The after-action report frame","scenario":"The flood response is over and your after-action report is due to the emergency management committee. The raw material is sixty pages of logs, and your team's draft is organized day by day. The committee needs to know what worked, what failed, and what changes.","task":"Write the report's 3 top-level headings as claims and one sentence under each.","tips":["Headings as findings: 'evacuation worked; alerting failed; mutual aid needs a pre-signed agreement.'","Chronology is the appendix, not the spine.","Each 'what failed' pairs with a 'what changes' — findings without fixes read as excuses."],"focus":["structure","impact"]},
    {"id":"structure-gov-senior-10","level":"senior","profession":"publicservice","title":"Ten stakeholder concerns, three themes","scenario":"Public consultation on the zoning reform produced ten recurring concerns, and your summary to the planning board currently lists all ten as bullets of equal weight. Board members need to see the pattern, not the pile.","task":"Group the concerns into 3 named themes and write the summary's opening sentence.","tips":["Themes should explain, not just contain: 'most concerns reduce to parking, process trust, and neighbourhood character.'","Report the distribution — which theme dominated — so weight is visible.","Keep the raw list as an appendix for credibility."],"focus":["structure","clarity"],"placeholder":"The 214 comments reduce to three concerns: parking, trust in the process, and neighbourhood character."},
    {"id":"structure-gov-senior-11","level":"senior","profession":"publicservice","title":"The annual report readers actually read","scenario":"Your department's annual report opens with the director's message, then history, then org chart, then — on page nine — results. Councilmembers, journalists, and residents all quit before page nine.","task":"Write the new opening: one governing sentence on the year, then 3 headline results.","tips":["Lead with the year's verdict in one sentence, backed by the three results that prove it.","Structure for the skimmer: everything essential on page one.","The org chart has never persuaded anyone — move it to the back."],"focus":["structure","impact"]},
    {"id":"structure-gov-senior-12","level":"senior","profession":"publicservice","title":"The briefing note discipline","scenario":"Your ministry's briefing-note template has sections — Issue, Background, Considerations, Recommendation — but your analysts pour everything into Background and leave Recommendation as one thin line. The deputy reads Issue and Recommendation only.","task":"Write the Issue and Recommendation sections for a note seeking approval to pilot online licence renewal, 1-2 sentences each.","tips":["Issue states the decision needed, not the topic area.","Recommendation carries the specifics: what, cost, when — it must stand alone.","If Background were deleted, the note should still work."],"focus":["structure","concision"]},
    {"id":"structure-gov-senior-13","level":"senior","profession":"publicservice","title":"The town hall agenda that manages the heat","scenario":"You are chairing a town hall on the proposed shelter site — a hot room, guaranteed. An unstructured open mic will become two hours of the angriest voices. You need a structure that gets information out and every concern heard.","task":"Write the 3-part meeting structure you will announce at the top, one sentence each.","tips":["Announce the structure first — it is your contract with the room.","Put facts before feedback: fifteen minutes of what is actually proposed.","Structure the input: themed rounds or cards beat open-mic attrition."],"focus":["structure","audience"]},
    {"id":"structure-gov-senior-14","level":"senior","profession":"publicservice","title":"The capital plan pitch","scenario":"Your five-year capital plan asks council for $120M across forty projects. The current presentation lists projects by division. Council will fund a story, not a spreadsheet — and right now there is no story.","task":"Write the governing idea and 3 groupings that turn forty projects into an argument.","tips":["Group by public outcome — safety, growth, state-of-good-repair — not by which division owns them.","The governing idea should say what the city gets for $120M in one sentence.","Name the consequence of the unfunded alternative under each group."],"focus":["structure","impact"],"placeholder":"This plan keeps what we own from failing, builds for the growth already permitted, and"},
    {"id":"structure-gov-senior-15","level":"senior","profession":"publicservice","title":"The survey results, organized to land","scenario":"The employee engagement survey came back with scores across eighteen dimensions. Your all-staff summary currently reports all eighteen in questionnaire order. The real story: pride is high, trust in senior leadership is low, and workload sits in between.","task":"Write the opening 2 sentences that lead with the pattern, then name how you will structure the rest.","tips":["Lead with the honest pattern, including the unflattering part — staff know it anyway.","Structure by finding, not by questionnaire order.","Naming the low leadership-trust score yourself builds exactly that trust."],"focus":["structure","clarity"]},
    {"id":"structure-gov-senior-16","level":"senior","profession":"publicservice","title":"Testimony with a load-bearing frame","scenario":"You have five minutes of prepared testimony on the infrastructure funding bill. Your draft is one long paragraph of connected prose. Committee members will hear it once, over noise, while reading something else.","task":"Restructure the testimony: one-sentence position, 3 numbered reasons, one-sentence close.","tips":["Spoken structure must be audible: 'three reasons' and count them off.","One idea per reason, one number per reason.","The close repeats the position — the last sentence is what survives."],"focus":["structure","clarity"]},
    {"id":"structure-gov-senior-17","level":"senior","profession":"publicservice","title":"The options memo that ranks","scenario":"The minister asked for options on the aging courthouse: renovate, rebuild, or lease. Your draft describes each option at identical length with no comparative frame, forcing the minister to build the comparison herself.","task":"Write the memo's opening: the decision, your recommendation, and the one dimension that most differentiates the options — 3 sentences.","tips":["State the comparative frame: the options differ mainly on cost now vs. cost later.","Recommend one; present the others fairly against the same criteria.","Equal-length neutral descriptions outsource your job to the reader."],"focus":["structure","clarity"]},
    {"id":"structure-gov-senior-18","level":"senior","profession":"publicservice","title":"The MOU proposal skeleton","scenario":"You are proposing a data-sharing MOU to three partner agencies. Your draft proposal opens with legal boilerplate. Each agency head will decide based on what they give, what they get, and what risk they carry.","task":"Structure the proposal around those 3 questions and write one sentence under each.","tips":["Order the sections by the reader's decision logic: benefit, obligation, risk.","Symmetry sells — show each agency's give-get in the same frame.","Legal boilerplate follows agreement in principle, never precedes it."],"focus":["structure","audience"]},
    {"id":"structure-gov-senior-19","level":"senior","profession":"publicservice","title":"Talking points that nest","scenario":"You are prepping the mayor for a press conference on the transit expansion. Your draft gives her twelve equal talking points. Under questioning she will remember three at most, and the twelve don't tell her which three.","task":"Write the 1 core message and 3 supporting points, clearly ranked.","tips":["One message she cannot get wrong, three proofs beneath it.","Every question should have a bridge back to the core message.","Twelve points is abdication dressed as thoroughness."],"focus":["structure","concision"],"placeholder":"Core message: this expansion cuts the average east-side commute by 20 minutes, starting"},
    {"id":"structure-gov-senior-20","level":"senior","profession":"publicservice","title":"The strategic plan on one page","scenario":"The five-year departmental strategy your team spent months on is ninety pages. The board chair asked for 'the one-pager' — and the current attempt crams all six goals, eighteen objectives, and forty measures into small type.","task":"Write the one-pager's structure: the mission-level claim and 3 strategic priorities, one sentence each.","tips":["A one-pager is a hierarchy, not a compression — cut levels, not font size.","Three priorities with one measure each beats six goals with forty.","If everything is strategic, nothing is."],"focus":["structure","concision"]},
    {"id":"structure-gov-senior-21","level":"senior","profession":"publicservice","title":"The emergency plan brief","scenario":"You must brief new councilmembers on the emergency operations plan. The plan is 300 pages; your hour became twenty minutes. Members need to know their own role, the activation triggers, and the chain of command — in that order of likelihood they will need it.","task":"Write the 3-part structure of the brief and its opening sentence.","tips":["Structure by what the audience will actually need under stress: their role first.","The plan's own chapter order serves planners, not councilmembers.","Close with the one card they keep: who calls them, and whom they call."],"focus":["structure","audience"]},
    {"id":"structure-gov-senior-22","level":"senior","profession":"publicservice","title":"The complaint pattern report","scenario":"The ombudsman flagged that your department received 340 complaints last quarter. Your response report lists them by intake date. The pattern that matters: 60% trace to one confusing renewal form, 25% to call-center wait times, the rest scattered.","task":"Write the report's opening 2 sentences, structured around the pattern.","tips":["Lead with the concentration: most complaints have one fixable cause.","Structure the report by cause, sized by share, with the fix under each.","A date-ordered list hides the very insight that exonerates you."],"focus":["structure","precision"],"placeholder":"Sixty percent of last quarter's 340 complaints trace to a single cause: the redesigned renewal form."},
    {"id":"structure-gov-senior-23","level":"senior","profession":"publicservice","title":"The counterproposal, structured for the table","scenario":"You are presenting management's counterproposal in bargaining. Your draft walks the union team through the articles in contract order. The union's actual priorities are wages, scheduling, and job security — and your movement on each differs.","task":"Structure the presentation in 3 parts by the union's priorities and write the framing sentence.","tips":["Order by the other side's priorities — it signals you listened.","Lead each part with your movement, then your constraint.","Contract-article order buries your concessions where they earn nothing."],"focus":["structure","audience"]},
    {"id":"structure-gov-senior-24","level":"senior","profession":"publicservice","title":"The dashboard narrative","scenario":"Your quarterly performance dashboard goes to the board with forty metrics and no narrative. Three metrics moved materially this quarter — two improved, one declined. Board members either miss the story or invent their own.","task":"Write the 3-sentence narrative that should sit atop the dashboard.","tips":["Narrate only what moved and why; stable metrics get one clause.","Pair the declining metric with its cause and your response.","If you don't write the story, the board writes it for you."],"focus":["structure","precision"]},
    {"id":"structure-gov-senior-25","level":"senior","profession":"publicservice","title":"Thirty minutes becomes ten","scenario":"Your thirty-minute board update was just cut to ten because the agenda ran long. Your deck has six sections. Cutting evenly — rushing all six — would lose everything; the structure has to change, not just the pace.","task":"Name the one section you will keep in full, the 2 you will compress to a sentence each, and write your new opening line.","tips":["Cut sections, not seconds per slide.","Keep the decision-relevant section whole; summarize the informational ones.","Announce the triage: 'I'll focus on the funding decision and take questions on the rest.'"],"focus":["structure","concision"]}
  ],
  "cut-to-the-bone": [
    {"id":"concise-gov-senior-01","level":"senior","profession":"publicservice","title":"The nominalization factory","scenario":"Your policy shop drafted: 'The implementation of the utilization review process will result in the achievement of significant improvements in the facilitation of service delivery.' This sentence is going in a public document with your name on it.","task":"Rewrite the sentence in plain verbs, under 15 words.","tips":["Hunt the -tion words and convert each back to a verb.","Ask who does what: 'reviewing how we use X will improve Y.'","If a sentence has no human actor, it is hiding something."],"focus":["concision","clarity"],"placeholder":"Reviewing how we use staff will speed up service."},
    {"id":"concise-gov-senior-02","level":"senior","profession":"publicservice","title":"The public notice on a diet","scenario":"The road-closure notice drafted for mailboxes runs 220 words, opening with the municipal code authority for closures. Residents need four facts: which road, when, how long, and the detour.","task":"Rewrite the notice in under 50 words.","tips":["Lead with the four facts residents scan for.","Legal authority can be one citation line at the bottom.","Every word past necessity costs readers you cannot afford to lose."],"focus":["concision","audience"]},
    {"id":"concise-gov-senior-03","level":"senior","profession":"publicservice","title":"The hedge-choked recommendation","scenario":"Your draft to the board reads: 'It would seem that, in most circumstances, it might be advisable to consider potentially moving toward a phased approach, where feasible.' You actually believe the phased approach is right.","task":"Rewrite as one direct recommendation sentence.","tips":["Count the hedges — seem, might, consider, potentially, where feasible — and cut all of them.","Keep one honest qualifier only if the uncertainty is real and specific.","Hedging every clause reads as either fear or absence of a view."],"focus":["concision","impact"],"placeholder":"I recommend a phased approach, starting with the two largest offices."},
    {"id":"concise-gov-senior-04","level":"senior","profession":"publicservice","title":"The 200-word council memo, halved","scenario":"Your staff's council memo on the library hours pilot runs 200 words: background on the pilot's origins, methodology of the usage study, then the result — Sunday hours doubled visits at modest cost — and the recommendation to continue.","task":"Rewrite the memo in under 100 words without losing the decision-relevant content.","tips":["Result and recommendation survive; origins and methodology shrink to a clause.","Cut in passes: first whole sentences, then clauses, then words.","What council must know beats what staff did."],"focus":["concision","structure"]},
    {"id":"concise-gov-senior-05","level":"senior","profession":"publicservice","title":"The it-should-be-noted purge","scenario":"Your quarterly report draft contains 'it should be noted that' four times, plus 'it is important to highlight' and 'it is worth mentioning.' None of these phrases carries any content.","task":"Rewrite 2 such sentences from the report with the meta-commentary removed.","tips":["If it should be noted, just note it.","Meta-commentary is the writer clearing their throat in print.","The content that follows either earns attention or it doesn't — announcing it changes nothing."],"focus":["concision","clarity"]},
    {"id":"concise-gov-senior-06","level":"senior","profession":"publicservice","title":"The redundant-pair treaty","scenario":"The draft interagency agreement is littered with lawyerly pairs: 'full and complete,' 'each and every,' 'terms and conditions,' 'null and void,' 'cease and desist.' The plain-language review flagged all of them.","task":"Rewrite one clause of the agreement cutting every redundant pair.","tips":["In each pair, one word does all the work — keep that one.","Legal tradition is not legal necessity; plain-language statutes exist.","Read the result aloud: it should sound like a person."],"focus":["concision","precision"]},
    {"id":"concise-gov-senior-07","level":"senior","profession":"publicservice","title":"The five-paragraph email, five sentences","scenario":"Your draft email to peer directors about the shared-services timeline runs five paragraphs. It contains one date change, one new obligation for their teams, and one request for a named contact — wrapped in courtesy and context.","task":"Rewrite the email in 5 sentences or fewer.","tips":["One sentence per fact: date, obligation, ask.","Courtesy fits in the greeting and sign-off, not in paragraphs.","Directors forward short emails; long ones die in inboxes."],"focus":["concision","clarity"],"placeholder":"The shared-services go-live moves to September 8. This means your teams will need to"},
    {"id":"concise-gov-senior-08","level":"senior","profession":"publicservice","title":"The executive summary that isn't","scenario":"The consultant's report on facility consolidation has a two-page 'executive summary' that summarizes nothing — it previews the report's structure. The board gets the report tomorrow, and the real findings are ten pages deep.","task":"Write a true executive summary in 4-5 sentences: findings, recommendation, cost, decision needed.","tips":["A summary states conclusions, not the order in which topics appear.","'This report examines...' is a table of contents in disguise.","Write it so the board could decide without opening the report — that is the test."],"focus":["concision","structure"]},
    {"id":"concise-gov-senior-09","level":"senior","profession":"publicservice","title":"The sixty-word slide","scenario":"Slide four of your legislature presentation has 60 words in three dense bullets. Members will read the slide instead of listening to you, and finish neither.","task":"Rewrite the slide's content in 20 words or fewer.","tips":["The slide is the billboard; you are the argument.","One claim per slide, one number if it earns its place.","If everything you say is on the slide, one of you is redundant."],"focus":["concision","impact"]},
    {"id":"concise-gov-senior-10","level":"senior","profession":"publicservice","title":"The passive-voice incident report","scenario":"The public incident summary reads: 'Errors were made in the processing of applications, and delays were experienced by applicants.' The passive constructions dodge the one thing readers want: who did what and who fixes it.","task":"Rewrite the 2 sentences in active voice with named actors.","tips":["Passive voice in accountability documents reads as evasion — because it is.","Name the actor: the department misprocessed, the vendor's system failed.","Active voice is shorter, which is a free bonus."],"focus":["concision","clarity"],"placeholder":"The department misprocessed 1,200 applications between March and May."},
    {"id":"concise-gov-senior-11","level":"senior","profession":"publicservice","title":"The acronym-saturated update","scenario":"Your update to the executive committee reads: 'The IGA with DOT requires EA completion per NEPA before the TIP amendment, pending MPO approval.' Two committee members are new and will not admit they followed none of it.","task":"Rewrite the sentence spelling out or replacing every acronym, in plain sequence.","tips":["Each acronym is a small tax on every reader; five in a sentence is a wall.","Replace with the function: 'the environmental review required by federal law.'","Keep an acronym only if the audience uses it daily."],"focus":["concision","audience"]},
    {"id":"concise-gov-senior-12","level":"senior","profession":"publicservice","title":"Ninety seconds at the podium","scenario":"The mayor gave you ninety seconds at the press conference to explain the new emergency-alert system. Your drafted remarks run four minutes. Reading faster is not the answer.","task":"Cut the remarks to 3-4 sentences that fit ninety seconds spoken slowly.","tips":["Pick the one thing residents must do: sign up, here's how.","Cut features; keep the action and the benefit.","Ninety seconds spoken well beats four minutes rushed."],"focus":["concision","audience"]},
    {"id":"concise-gov-senior-13","level":"senior","profession":"publicservice","title":"The service-disruption apology","scenario":"Transit service failed during Monday's storm and your draft apology runs 300 words, half of it explaining the storm's meteorology. Riders want acknowledgment, cause in one line, and what changes.","task":"Rewrite the apology in 4 sentences.","tips":["Acknowledge plainly in sentence one — no 'we regret any inconvenience.'","One sentence of cause; residents lived the storm, skip the weather report.","End on the concrete change, not on sentiment."],"focus":["concision","audience"],"placeholder":"On Monday we failed the riders who depend on us: 40% of routes ran late or not at all."},
    {"id":"concise-gov-senior-14","level":"senior","profession":"publicservice","title":"The grant abstract word limit","scenario":"The federal application allows a 150-word abstract. Your program team's draft is 410 words and tries to mention every program component, partner, and outcome measure.","task":"Write the abstract in under 150 words — or draft its first 3 sentences within that discipline.","tips":["The abstract sells the need, the approach, and the outcome — components are for the narrative.","Cut partners and measures to counts: 'six partners, three outcome measures.'","Reviewers read abstracts to decide how carefully to read the rest."],"focus":["concision","structure"]},
    {"id":"concise-gov-senior-15","level":"senior","profession":"publicservice","title":"The job posting nobody finishes","scenario":"Your deputy director posting runs 900 words, opening with three paragraphs about the department's history and mission framework. Strong candidates skim postings; this one loses them before the role appears.","task":"Write the posting's first 3 sentences: the role, the impact, the one must-have.","tips":["Lead with what the person will actually do and own.","Mission history compresses to one confident clause.","Every requirement listed filters someone out — list only the real ones."],"focus":["concision","audience"]},
    {"id":"concise-gov-senior-16","level":"senior","profession":"publicservice","title":"The RFP summary for bidders","scenario":"The pre-bid conference is tomorrow and your RFP overview slide deck restates entire RFP sections verbatim. Bidders have read the RFP; they came to learn what you actually care about.","task":"Write the 3-sentence 'what we actually care about' summary for bidders.","tips":["State the evaluation weightings and the differentiator in plain terms.","Verbatim restatement wastes the one meeting where you can add signal.","Brevity here improves the bids you get back."],"focus":["concision","impact"]},
    {"id":"concise-gov-senior-17","level":"senior","profession":"publicservice","title":"The committee cover memo","scenario":"Your cover memo transmitting the 80-page consultant study to the committee currently summarizes all nine chapters. A cover memo has one job: tell the committee what the study concluded and what you want them to do with it.","task":"Write the cover memo in 3-4 sentences.","tips":["Conclusion, your position on it, and the requested action — that is the whole memo.","Chapter summaries duplicate the table of contents.","Under one page is a courtesy; under half a page is a gift."],"focus":["concision","structure"],"placeholder":"The study concludes consolidation saves $2.3M annually with no service reduction. I concur and request"},
    {"id":"concise-gov-senior-18","level":"senior","profession":"publicservice","title":"The thirty-second radio actuality","scenario":"The station wants a thirty-second recorded statement on the recycling program change. Your communications draft is ninety seconds and front-loads the program's history since 2009.","task":"Write the statement in 2-3 sentences that fit thirty seconds.","tips":["What changes, when, and what residents do — nothing else fits.","History is the first cut, adjectives the second.","Time it aloud; radio does not round down."],"focus":["concision","audience"]},
    {"id":"concise-gov-senior-19","level":"senior","profession":"publicservice","title":"The over-explained decision","scenario":"You denied a vendor's protest and your draft letter explains the decision from four angles, restating the same rationale in different words each time. Repetition reads as insecurity, and each restatement is new material for their lawyer.","task":"Rewrite the decision rationale once, in 2-3 sentences, and stop.","tips":["State the ground for denial once, precisely, and end.","Each rephrasing creates a new surface for challenge.","Confidence is one clean paragraph; anxiety is four."],"focus":["concision","precision"]},
    {"id":"concise-gov-senior-20","level":"senior","profession":"publicservice","title":"The speech's first minute","scenario":"Your State of the Department speech opens with two minutes of thanking dignitaries, acknowledging the organizing committee, and reflecting on the venue. The room's attention is highest in the first thirty seconds, and you are spending it on protocol.","task":"Write a new opening 2 sentences that put the year's headline first, then a single line of thanks.","tips":["Spend peak attention on the message, not the protocol.","One gracious sentence of thanks covers everyone; names can close the speech.","The first sentence should be quotable — write it last, place it first."],"focus":["concision","impact"]},
    {"id":"concise-gov-senior-21","level":"senior","profession":"publicservice","title":"The FAQ that answers twice","scenario":"The public FAQ for the new parking permit system answers each question with a paragraph that restates the question, gives background, then answers. Residents scan FAQs; they do not read them.","task":"Rewrite 2 FAQ answers at one sentence each.","tips":["Answer first — often the answer is one clause.","Never restate the question; the question is printed right there.","If an answer needs background, the question is probably two questions."],"focus":["concision","audience"],"placeholder":"Q: Do existing permits carry over? A: Yes, until their printed expiry date."},
    {"id":"concise-gov-senior-22","level":"senior","profession":"publicservice","title":"Cutting legal review without losing it","scenario":"Legal reviewed your public statement on the settlement and returned it doubled in length, every sentence cushioned. You must honor the substance of legal's protections while making it readable — the current draft protects the city from everyone, including readers.","task":"Rewrite one legally-cushioned sentence so it stays accurate but reads plainly.","tips":["Keep the legal substance — the qualifier that matters — and cut the redundant armor.","'The city does not admit liability' can survive; three restatements of it cannot.","Negotiate with legal over specific words, not whole drafts."],"focus":["concision","precision"]},
    {"id":"concise-gov-senior-23","level":"senior","profession":"publicservice","title":"The overtime memo's warm-up laps","scenario":"Your memo restricting discretionary overtime opens with two paragraphs about fiscal stewardship, shared sacrifice, and the budget environment before stating the new rule. Supervisors will search for the rule and skip your framing anyway.","task":"Rewrite the memo to state the rule in sentence one, with one sentence of rationale.","tips":["Policy memos are reference documents — the rule goes first.","One sentence of why is respect; two paragraphs is throat-clearing.","Supervisors need the effective date and the exception process visible at a glance."],"focus":["concision","clarity"],"placeholder":"Effective March 1, all discretionary overtime requires division-director approval in advance."},
    {"id":"concise-gov-senior-24","level":"senior","profession":"publicservice","title":"The witness statement, trimmed","scenario":"Your written testimony for the record runs eleven pages, but the committee accepts five and reads one. Your team resists every cut, arguing each section 'provides important context.'","task":"Write the one-paragraph version — 4-5 sentences — you would keep if only a paragraph survived.","tips":["Decide what the committee must retain, and protect only that.","'Important context' that no one reads protects nothing.","The written record can be long; the read version cannot."],"focus":["concision","impact"]},
    {"id":"concise-gov-senior-25","level":"senior","profession":"publicservice","title":"The condolence with no boilerplate","scenario":"An employee of thirty years died suddenly, and you are writing the note to staff. The HR draft is full of institutional phrases — 'valued member of our organization,' 'thoughts go out.' The department knew her; the note should sound like it.","task":"Write a 3-sentence note in plain, human language.","tips":["Say her name, what she actually did, and one true specific thing about her.","Cut every phrase you have read in another organization's notice.","Short and true honors better than long and generic."],"focus":["concision","audience"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-gov-senior-01","level":"senior","profession":"publicservice","title":"'Significant progress' at committee","scenario":"Your testimony draft says the department has made 'significant progress' on the permit backlog. The committee heard 'significant progress' last year too, and the chair has the transcript. Only numbers will read as different this time.","task":"Rewrite the claim with the numbers a skeptical chair would accept.","tips":["Replace 'significant' with the count: backlog from X to Y, over what period.","Anchor to the baseline the committee already knows — last year's figure.","If the number is unimpressive, say it plainly and explain the constraint; spin gets found."],"focus":["precision","impact"],"placeholder":"The permit backlog has fallen from 4,200 to 1,850 files since January — a 56% reduction."},
    {"id":"precision-gov-senior-02","level":"senior","profession":"publicservice","title":"'As soon as practicable'","scenario":"Your management response to the auditor general commits to implementing each recommendation 'as soon as practicable.' The auditor's follow-up report will grade you against your own words, and 'practicable' is ungradeable — which is exactly why the draft says it.","task":"Rewrite one commitment with a date, an owner, and a verifiable deliverable.","tips":["A commitment without a date is a sentiment, not a commitment.","Name the accountable position, not 'the department.'","Pick a date you can defend in the follow-up audit — then say that date."],"focus":["precision","clarity"],"placeholder":"The division director will implement the new intake controls by September 30 and report completion to"},
    {"id":"precision-gov-senior-03","level":"senior","profession":"publicservice","title":"'Many residents have told us'","scenario":"Your council report justifies the crosswalk program because 'many residents have expressed concerns about pedestrian safety.' A councilmember who opposes the spending will ask: how many, from where, and how were they counted?","task":"Rewrite the sentence with countable, sourced evidence.","tips":["'Many' invites the question; a number answers it before it's asked.","Say the source: 311 calls, survey responses, petition signatures.","Note the collision data alongside the complaints — sentiment plus incident counts."],"focus":["precision","structure"],"placeholder":"We received 214 pedestrian-safety requests through 311 in 2025, concentrated at six intersections that also"},
    {"id":"precision-gov-senior-04","level":"senior","profession":"publicservice","title":"The crime stat with a spine","scenario":"The mayor's office wants you to say crime is 'trending in the right direction.' Property crime is down 12% but assaults are up 4%, and the crime reporter has the same data feed you do. A vague claim will be fact-checked into a scandal.","task":"Write 2 sentences that state both numbers honestly and still land the real story.","tips":["Give the precise figures with their baselines — the reporter will anyway.","Lead with the accurate overall picture, then the exception, unhidden.","Credibility on the bad number is what makes the good number believable."],"focus":["precision","audience"],"placeholder":"Property crime is down 12% year over year; assaults are up 4%, and here is what we are doing about"},
    {"id":"precision-gov-senior-05","level":"senior","profession":"publicservice","title":"'Operational efficiencies' has no dollar sign","scenario":"Your budget narrative claims the reorganization will deliver 'operational efficiencies across the department.' The finance committee has read that phrase in a decade of budget books and never once seen it audited as true.","task":"Rewrite the claim naming the specific savings and their dollar value.","tips":["Name what actually gets cheaper: positions, leases, licenses, overtime.","Attach a dollar figure and the year it lands.","If you cannot quantify it, do not claim it — unfunded efficiency claims cost credibility."],"focus":["precision","impact"],"placeholder":"Consolidating the two intake offices eliminates one lease ($180K/yr) and four vacant positions ($310K/yr) beginning FY28."},
    {"id":"precision-gov-senior-06","level":"senior","profession":"publicservice","title":"Forty pages, one insight","scenario":"The quarterly performance dashboard runs forty pages and the deputy minister has four minutes. Buried on page 23 is the finding that matters: wait times dropped everywhere except the two offices that didn't adopt the new triage model.","task":"Write the 2-sentence insight you would put on page one.","tips":["An insight is a comparison plus a cause, not a statistic.","Say what the data means for the decision in front of the deputy.","One insight stated clearly beats forty pages transmitted faithfully."],"focus":["clarity","impact"],"placeholder":"Wait times fell 30% at every office using the new triage model — and rose at the two that haven't adopted it."},
    {"id":"precision-gov-senior-07","level":"senior","profession":"publicservice","title":"'Soon' is not a road repair date","scenario":"A reporter asks when the collapsed section of Riverside Drive reopens. Your engineering team says 'soon, weather permitting' because they fear being held to a date. But 'soon' becomes the headline 'City won't say when road reopens.'","task":"Draft the spoken answer with a window and its condition, said plainly.","tips":["Give a bounded window: 'between the 15th and the 22nd.'","Name the one condition that moves it, so a slip is explained in advance.","A defensible range beats both a vague 'soon' and a brittle exact date."],"focus":["precision","audience"]},
    {"id":"precision-gov-senior-08","level":"senior","profession":"publicservice","title":"'Improved outcomes for youth'","scenario":"Your funding renewal for the youth employment program claims it 'improved outcomes for participating youth.' The provincial reviewer scores applications on measurable results, and this sentence measures nothing.","task":"Rewrite the outcomes claim with the numbers that survive review.","tips":["Name the outcome: employed at six months, credential earned, retention rate.","Give the comparison — against last year, a control group, or the regional average.","Report the denominator: 84 of 120 completers reads stronger than '70%.'"],"focus":["precision","structure"],"placeholder":"Of 120 participants, 84 were employed six months after completion — 70%, against a regional baseline of 51%."},
    {"id":"precision-gov-senior-09","level":"senior","profession":"publicservice","title":"Shelter numbers in a live briefing","scenario":"Mid-flood, the emergency operations centre asks you to brief council on shelter status. Your notes say 'shelters are nearing capacity.' Council will make an evacuation-zone decision on that sentence, and 'nearing' could mean 60% or 95%.","task":"Write the 2-sentence status with exact counts and the trigger point.","tips":["Occupancy, capacity, and rate of arrival — three numbers, no adjectives.","State the threshold that triggers the next action, so council sees the decision point.","In a crisis, precision is not pedantry; it is the decision input."],"focus":["precision","clarity"],"placeholder":"Shelters hold 1,140 of 1,400 capacity, with arrivals at roughly 60 per hour; at 1,300 we open the arena."},
    {"id":"precision-gov-senior-10","level":"senior","profession":"publicservice","title":"'Well-attended' consultation","scenario":"Your engagement summary calls the rezoning consultation 'well-attended and broadly supportive.' The opposing residents' association counted the room: 40 people, 15 of them city staff. Your summary is about to be read aloud at council, unkindly.","task":"Rewrite the attendance and support claims with honest numbers.","tips":["Report the count and who was in it — inflating attendance hands your critics the story.","'Broadly supportive' needs a ratio: comments for, against, mixed.","Small honest numbers plus a plan to reach more people beats big vague ones."],"focus":["precision","audience"],"placeholder":"Twenty-five residents attended; of 62 written comments, 38 supported the rezoning, 19 opposed, 5 were mixed."},
    {"id":"precision-gov-senior-11","level":"senior","profession":"publicservice","title":"The percentage without a base","scenario":"Your draft release celebrates that complaints about the new licensing portal are 'down 50% month over month.' The base: from 4 complaints to 2. If a reporter finds the raw numbers, the release becomes a joke.","task":"Rewrite the claim so the percentage and the base travel together.","tips":["Small-base percentages mislead — give the raw counts alongside.","Ask whether the number is even worth claiming; sometimes the honest move is silence.","Use volume context: 2 complaints across 11,000 transactions is the real story."],"focus":["precision","concision"],"placeholder":"The portal processed 11,000 renewals in March with two complaints, down from four in February."},
    {"id":"precision-gov-senior-12","level":"senior","profession":"publicservice","title":"Vendor 'performance concerns'","scenario":"You are recommending against renewing the snow-clearing contract, and your memo cites 'ongoing performance concerns.' The vendor will appeal, and 'concerns' is not a ground; missed service standards with dates are.","task":"Rewrite the justification as specific, documented failures.","tips":["Cite the SLA, the standard, and the miss: route completion under 80% on six storm events.","Dates and counts turn an opinion into a record.","Write it as the exhibit it will become at the appeal hearing."],"focus":["precision","structure"],"placeholder":"The contractor completed under 80% of assigned routes within the 12-hour standard on six of nine storm events, documented"},
    {"id":"precision-gov-senior-13","level":"senior","profession":"publicservice","title":"Answering the union's anecdote","scenario":"At the bargaining table, the union president describes one inspector working 70-hour weeks and asserts the whole division is burning out. Your instinct is to dismiss the anecdote; the better move is to answer it with the full distribution.","task":"Draft the spoken response that puts the real numbers next to the story, respectfully.","tips":["Acknowledge the individual case as real before citing the average.","Give the distribution, not just the mean: median hours, and how many exceed 50.","Precision here is respect — it shows you actually looked at their people's hours."],"focus":["precision","audience"]},
    {"id":"precision-gov-senior-14","level":"senior","profession":"publicservice","title":"Median, not average","scenario":"The minister will be asked about ER wait times. The average is 4.1 hours, dragged up by a few extreme cases; the median is 2.8. Whichever number goes in the briefing note will be the number she says, and the number she defends.","task":"Write the briefing line that gives her the right number with its meaning.","tips":["Choose the statistic that answers the actual question: what a typical patient waits.","Give both numbers with one clause explaining the gap.","Never send a minister out with a number you can't explain in one sentence."],"focus":["precision","clarity"],"placeholder":"A typical patient waits 2.8 hours (the median); the 4.1-hour average reflects a small number of complex cases that"},
    {"id":"precision-gov-senior-15","level":"senior","profession":"publicservice","title":"Write it FOI-ready","scenario":"Your internal memo on the landfill odour complaints says the situation is 'being managed' and residents' concerns are 'somewhat overstated.' Everything you write is one access-to-information request from the front page.","task":"Rewrite the two phrases so the memo is accurate, specific, and publishable.","tips":["'Being managed' becomes the actual actions and dates.","Never characterize residents' concerns — characterize the measurements.","The FOI test is not about hiding; it's about writing precisely enough to stand in public."],"focus":["precision","audience"],"placeholder":"Odour readings exceeded the guideline on 3 of 30 monitoring days in April; we installed additional cover"},
    {"id":"precision-gov-senior-16","level":"senior","profession":"publicservice","title":"'Comparable jurisdictions' — name them","scenario":"Your report claims the proposed user fee is 'in line with comparable jurisdictions.' The first question at committee will be: which ones, and what do they charge? Right now the answer lives in an analyst's spreadsheet, not your report.","task":"Rewrite the claim naming three jurisdictions and their figures.","tips":["Name the cities and the fees — a checkable claim earns trust before it's checked.","Pick genuinely comparable ones; a cherry-picked list gets dismantled in one question.","State where your proposal sits in the range: middle, low, high."],"focus":["precision","impact"],"placeholder":"Hamilton charges $85, Waterloo $92, and Halifax $78 for the equivalent permit; our proposed $88 sits mid-range."},
    {"id":"precision-gov-senior-17","level":"senior","profession":"publicservice","title":"The pilot that isn't a citywide result","scenario":"The supervised bike-lane pilot cut injuries 40% on one corridor, and the advocacy groups want you to promise 40% citywide. Your report needs to carry the good result without overclaiming what one corridor proves.","task":"Write 2 sentences that state the result and its honest limits.","tips":["Report the pilot number precisely, with its scope: one corridor, eight months.","Say what would confirm it scales — and what's already planned to find out.","Calibrated claims survive contact with the next data release; inflated ones don't."],"focus":["precision","clarity"],"placeholder":"On the Elm Street pilot corridor, cycling injuries fell 40% over eight months. Whether that holds citywide"},
    {"id":"precision-gov-senior-18","level":"senior","profession":"publicservice","title":"'Aging infrastructure' with a number","scenario":"Every budget season your capital request says the department faces 'aging infrastructure challenges.' So does every other department. This year you have the asset condition data, and specificity is your competitive advantage in a constrained budget.","task":"Rewrite the opening claim with the asset numbers that distinguish your request.","tips":["Give the condition ratings: how many assets in poor or critical, out of how many.","Attach the consequence with a probability or history: failures per year, cost per failure.","'Aging' is universal; '31% past design life' is fundable."],"focus":["precision","impact"],"placeholder":"Thirty-one percent of our 210 pump stations are past design life; we recorded 14 failures last year, up from 6"},
    {"id":"precision-gov-senior-19","level":"senior","profession":"publicservice","title":"'It has been suggested that'","scenario":"Your policy brief hedges every contested point with phantom attribution: 'it has been suggested,' 'some have argued,' 'there is a perception that.' The deputy minister wrote in the margin: 'By whom? Says who?'","task":"Rewrite 2 of these sentences with real attribution or an owned judgment.","tips":["Name the source: the auditor, the union, the 2024 evaluation, three stakeholder submissions.","If no one actually said it, it's your judgment — own it with 'I assess.'","Phantom attribution reads as either cowardice or invention; both cost you."],"focus":["precision","clarity"],"placeholder":"The union's March submission argues the ratio is unsafe; the 2024 external evaluation reached the same conclusion."},
    {"id":"precision-gov-senior-20","level":"senior","profession":"publicservice","title":"The ridership decline, unspun","scenario":"Transit ridership is down 8% and council will demand an explanation. Your team's draft attributes it broadly to 'shifting post-pandemic travel patterns.' The route-level data shows something more specific: two-thirds of the decline is on the five routes cut to hourly service last spring.","task":"Write the 2-sentence explanation the data actually supports.","tips":["Follow the decomposition: where exactly is the decline concentrated?","A specific cause you own is more credible than a vague trend you blame.","The precise diagnosis also carries the remedy — restore frequency, restore riders."],"focus":["precision","structure"],"placeholder":"Two-thirds of the 8% decline sits on the five routes reduced to hourly service in April; system-wide"},
    {"id":"precision-gov-senior-21","level":"senior","profession":"publicservice","title":"Cost per outcome","scenario":"The $12M homelessness program is defended in your draft as 'a major investment in our most vulnerable residents.' The councilmember who will decide the vote thinks in unit costs, and right now she has no idea what $12M buys.","task":"Translate the budget into cost-per-outcome terms in 2 sentences.","tips":["Divide: dollars per person housed, per shelter night avoided, per case managed.","Compare the unit cost to the alternative — emergency response, hospital nights.","Cost-per-outcome is the sentence that survives into the council debate."],"focus":["precision","audience"],"placeholder":"The $12M houses 400 people at $30,000 each — against roughly $55,000 per person per year in emergency"},
    {"id":"precision-gov-senior-22","level":"senior","profession":"publicservice","title":"The estimate with an honest range","scenario":"Council wants a cost for the recreation centre before design is finished. A single number will be wrong and remembered forever; refusing a number reads as evasion. The professional answer is a range with a confidence class.","task":"Write the 2-sentence estimate answer for the council report.","tips":["Give the range and name the estimate class: 'a Class D estimate, minus 30 to plus 50 percent.'","Say what narrows it and when: schematic design, complete in June.","Ranges age well; point estimates become the number you 'blew through.'"],"focus":["precision","structure"],"placeholder":"At concept stage the range is $38M to $55M — a Class D estimate. Schematic design, complete in June, will narrow"},
    {"id":"precision-gov-senior-23","level":"senior","profession":"publicservice","title":"Correcting the record","scenario":"Reviewing the transcript, you realize you told the committee the program served 8,000 households; the verified figure is 6,400. No one has noticed yet. The correction letter you write now determines whether this is a footnote or a credibility story.","task":"Write the 2-3 sentence correction for the committee clerk.","tips":["State the wrong number, the right number, and the cause, in that order — no cushioning.","Correct proactively and fast; being caught converts an error into a concealment.","Do not over-apologize: one sentence of correction, one of cause, done."],"focus":["precision","concision"],"placeholder":"In my testimony of May 12 I stated the program served 8,000 households; the verified figure is 6,400. The error"},
    {"id":"precision-gov-senior-24","level":"senior","profession":"publicservice","title":"'A public safety risk' — which one?","scenario":"Your memo urging closure of the aging parkade says it 'poses a public safety risk.' That phrase triggers either panic or dismissal, depending on the reader. What you actually have is an engineering report with specific findings.","task":"Rewrite the risk statement with the hazard, the likelihood, and who is exposed.","tips":["Name the failure mode the engineers actually flagged.","Quantify exposure: how many vehicles, how many daily users.","Precision calibrates the response — vagueness produces either overreaction or none."],"focus":["precision","clarity"],"placeholder":"The consulting engineer found spalling on 12 of 40 support columns; the structure remains safe for current loads but"},
    {"id":"precision-gov-senior-25","level":"senior","profession":"publicservice","title":"One number for the scrum","scenario":"You have ninety seconds outside the council chamber and a dozen defensible statistics about the housing program. The reporters will keep one number. Choosing it is the whole job.","task":"Pick the single statistic you would lead with and deliver it in one spoken sentence with its source.","tips":["Choose the number closest to what residents experience, not what the department tracks.","Say the source in the same breath — a sourced number travels further.","One number repeated is a message; five numbers is noise."],"focus":["precision","impact"]}
  ],
  "executive-presence": [
    {"id":"presence-gov-senior-01","level":"senior","profession":"publicservice","title":"The options memo that won't choose","scenario":"Your staff's memo to the minister lays out three options for the licensing backlog with scrupulous neutrality and no recommendation. Ministers pay senior officials to recommend. Neutrality at your level reads as either indecision or self-protection.","task":"Write the recommendation paragraph: your pick, owned, with the reason.","tips":["Say 'I recommend Option 2' — first person, no passive cover.","Give the deciding reason in one sentence, not a re-summary of all three.","Acknowledge the runner-up's main advantage in a clause; it shows you weighed it."],"focus":["clarity","impact"],"placeholder":"I recommend Option 2: contracting the intake surge while we hire. It clears the backlog by Q3, and unlike Option 1"},
    {"id":"presence-gov-senior-02","level":"senior","profession":"publicservice","title":"Three points, announced","scenario":"Your ten minutes of budget testimony covers staffing, capital, and the new service standard, but the draft wanders between them and back. Committee members can't take notes on a wandering witness, and what they can't note, they can't repeat.","task":"Write the signpost opening: one sentence framing your three points, then the first point's opening line.","tips":["'I'll cover three things: X, Y, Z' — then actually keep that order.","Number the points aloud as you reach them; it lets the room re-find its place.","A signposted witness sounds in command even when the content is contested."],"focus":["structure","clarity"],"placeholder":"I'll cover three things this morning: what the backlog costs, what fixes it, and what it requires from this committee. First"},
    {"id":"presence-gov-senior-03","level":"senior","profession":"publicservice","title":"Fact, then judgment, labeled","scenario":"Your briefing to the minister on the protest outside the constituency office blends what happened with what you think will happen, unlabeled. If she can't tell your facts from your forecasts, she can't calibrate her trust in either.","task":"Rewrite 3 sentences of the briefing so facts and judgments are explicitly separated.","tips":["Facts get sources; judgments get 'I assess' or 'my judgment is.'","Give your confidence level on the forecast — likely, possible, unlikely.","Ministers forgive wrong forecasts that were labeled; they don't forgive blurred ones."],"focus":["precision","structure"],"placeholder":"Fact: roughly 60 protesters attended, no incidents, organizers have filed for a permit next Saturday. My assessment:"},
    {"id":"presence-gov-senior-04","level":"senior","profession":"publicservice","title":"Unstacking the hedges at council","scenario":"Your rehearsal answer on the landfill siting begins: 'I think we could probably say that, in most scenarios, the site would likely be viable.' Four hedges before the noun. Council hears an official who doesn't believe his own file.","task":"Rewrite the answer with one calibrated qualifier, spoken with a full stop.","tips":["Pick the one honest hedge and delete the rest.","Say what you're sure of first, then the genuine uncertainty, separately.","End on a period, not a trailing clause — the full stop is half the confidence."],"focus":["concision","impact"],"placeholder":"The site is viable. The one open question is groundwater flow, and drilling results will settle it by August."},
    {"id":"presence-gov-senior-05","level":"senior","profession":"publicservice","title":"'Mistakes were made'","scenario":"The draft statement on the benefits-payment error says 'errors occurred in the processing system and steps are being taken.' No actor, no owner, no one taking a step. The passive voice is the sound of an institution hiding.","task":"Rewrite the statement in active voice with your department as the actor.","tips":["'We miscalculated 3,100 payments' — subject, verb, number.","Name who fixes it and by when, also in active voice.","Ownership in the first sentence is what makes the fix in the second believable."],"focus":["clarity","impact"],"placeholder":"We miscalculated 3,100 benefit payments in March. We will repay every affected recipient by May 15, with"},
    {"id":"presence-gov-senior-06","level":"senior","profession":"publicservice","title":"The interim director's first hello","scenario":"You've been named interim director after your predecessor's abrupt exit, and tomorrow you face 400 staff who are wondering whether you're a caretaker or a leader. 'Interim' is in your title; it doesn't have to be in your voice.","task":"Draft your spoken opening 3 sentences to the all-staff meeting.","tips":["State what will not change and what you will decide — both, plainly.","Don't disclaim your authority ('I'm just keeping the seat warm'); you hold the accountability either way.","One concrete near-term commitment beats a paragraph of vision."],"focus":["audience","impact"]},
    {"id":"presence-gov-senior-07","level":"senior","profession":"publicservice","title":"Calm at the scrum","scenario":"Six reporters, cameras on, and the first question is a shouted 'Who approved this?' Presence in a scrum isn't volume — it's a measured pace, complete sentences, and answers that end where you decide they end.","task":"Draft your first spoken answer: 2 sentences, delivered at a deliberate pace, ending firmly.","tips":["Answer in complete, short sentences; fragments read as rattled.","Slow down 20% from conversational pace — on camera it sounds like command.","Finish your sentence, then stop. The silence is theirs to fill, not yours."],"focus":["clarity","audience"]},
    {"id":"presence-gov-senior-08","level":"senior","profession":"publicservice","title":"Your name, not the consultant's","scenario":"Presenting the service review, your draft attributes everything to the consultants: 'KPMG recommends,' 'the consultants found.' Council didn't hire KPMG's judgment for the next thirty years; they hired yours. Hiding behind the report reads as pre-positioning for failure.","task":"Rewrite the recommendation sentence so you own it, with the consultants as support.","tips":["'I recommend' first; 'consistent with the external review' second.","Cite the consultants as evidence, not as the decision-maker.","If you wouldn't own it without the report, don't recommend it with one."],"focus":["clarity","impact"],"placeholder":"I recommend consolidating the six service counters into three. The external review reached the same conclusion, and"},
    {"id":"presence-gov-senior-09","level":"senior","profession":"publicservice","title":"First briefing, new deputy minister","scenario":"The incoming deputy minister has allotted you fifteen minutes to introduce your branch. She is deciding, in those fifteen minutes, whether you are someone she can send into a room alone. Sounding decided about your own file is the audition.","task":"Write your opening 3 sentences: what the branch does, its one big problem, and your plan for it.","tips":["State the problem before she has to find it — surfacing your own bad news is presence.","Have a plan with a date attached, even if it's provisional.","Skip the org-chart tour; describe the branch by what it delivers."],"focus":["structure","impact"],"placeholder":"My branch licenses 40,000 operators a year. Our problem is a 90-day approval time that should be 30, and"},
    {"id":"presence-gov-senior-10","level":"senior","profession":"publicservice","title":"Disagreeing with the minister","scenario":"The minister favours announcing the program expansion before the evaluation lands. You believe that's a mistake she'll wear publicly. Your job is fearless advice, delivered once, clearly, in language that respects that the decision is hers.","task":"Write the 3-sentence advice: your disagreement, the reason, and the acknowledgment of her call.","tips":["State the recommendation against, plainly — no 'some might suggest caution.'","One concrete consequence, not a parade of horribles.","Close with 'the decision is yours, and I'll implement either way' — and mean it."],"focus":["clarity","audience"],"placeholder":"I recommend against announcing before the evaluation reports. If it shows weak results in March, the announcement becomes"},
    {"id":"presence-gov-senior-11","level":"senior","profession":"publicservice","title":"'We're looking into it' upgraded","scenario":"Every briefing on the payroll system failure ends with 'we're continuing to look into it.' Four weeks in, that phrase has become an admission that no one is deciding anything. You have, in fact, decided things.","task":"Rewrite the status line as decisions made and the next decision's date.","tips":["'We decided X on Tuesday; we decide Y by Friday' — decisions, not activity.","'Looking into it' describes motion; leaders report direction.","Name the decision you have deliberately deferred, and why — deferral chosen is still command."],"focus":["clarity","structure"],"placeholder":"We've stopped the automated runs and moved 200 affected staff to manual pay. By Friday we decide whether"},
    {"id":"presence-gov-senior-12","level":"senior","profession":"publicservice","title":"Holding the town hall's first minute","scenario":"Two hundred residents are in the gym, angry about the water rate increase, and the microphone is yours first. Whoever frames the meeting owns it. A weak, apologetic opening hands the frame to the loudest voice in row three.","task":"Draft your spoken opening 3 sentences: why you're here, what you'll answer, what happens with what you hear.","tips":["Acknowledge the anger as legitimate in one sentence — then move, don't marinate.","Say concretely what tonight's input will change and by when.","Set the format with authority: 'I'll take questions for ninety minutes, and I'll answer them directly.'"],"focus":["audience","impact"]},
    {"id":"presence-gov-senior-13","level":"senior","profession":"publicservice","title":"Owning the least-bad option","scenario":"Every option for the failing bridge is painful: full closure, one-lane operation, or an expensive emergency repair. Your draft presents all three with equal misery and no recommendation, hoping council will choose. They will — badly — unless you lead.","task":"Write the recommendation paragraph that owns the least-bad option honestly.","tips":["Say it's the least-bad and why — pretending it's good insults the room.","Compare on the deciding factor only: safety, then cost, in that order.","'I recommend' carries more weight, not less, when the options are ugly."],"focus":["structure","impact"],"placeholder":"None of these options is good. I recommend one-lane operation with the repair in spring: it keeps the crossing open"},
    {"id":"presence-gov-senior-14","level":"senior","profession":"publicservice","title":"The roadmap sentence","scenario":"Your budget defense is twenty minutes across four program areas. Without a spoken map, the committee experiences it as an undifferentiated stream and interrupts wherever they like. With one, you control the terrain.","task":"Write the single roadmap sentence that opens the defense, then the transition line into section one.","tips":["Name the sections and the order — and promise where the money question gets answered.","Transitions restate progress: 'That's staffing. Second, capital.'","A mapped presentation gets interrupted less; members wait for the announced section."],"focus":["structure","clarity"],"placeholder":"I'll walk through four areas — staffing, capital, the new standard, and risks — and the total ask comes at the end."},
    {"id":"presence-gov-senior-15","level":"senior","profession":"publicservice","title":"'Who is accountable?'","scenario":"After the procurement failure, a councilmember asks, on camera: 'Who exactly is accountable for this?' Every deflection you've ever heard — 'there were many factors,' 'accountability is shared' — is available. None of them is the answer.","task":"Draft the spoken 2-sentence answer that takes accountability cleanly.","tips":["'I am. The division reports to me, and the failure happened on my watch.'","Then pivot once to the fix — accountability without a remedy is theatre.","Don't distribute blame downward in the same breath you claim accountability."],"focus":["clarity","impact"]},
    {"id":"presence-gov-senior-16","level":"senior","profession":"publicservice","title":"The apology that has a subject","scenario":"Legal has drafted the apology for the data exposure: 'The department regrets that circumstances resulted in information being accessible.' Nobody did anything, circumstances just resulted. Residents can tell the difference between an apology and a fog machine.","task":"Rewrite the apology in first person plural with a real verb.","tips":["'We left 2,000 files unsecured for six days' — the plain version is the credible version.","Apologize for the act, not for 'any concern this may have caused.'","Keep legal's substance (no liability admission beyond the facts) but lose the fog."],"focus":["clarity","audience"],"placeholder":"We left 2,000 residents' files accessible on an unsecured server for six days. That was our failure, and"},
    {"id":"presence-gov-senior-17","level":"senior","profession":"publicservice","title":"Confident about the uncertain","scenario":"Council asks whether the new intake model will hit its 30-day target. The honest answer is probably, not certainly. Presence is delivering calibrated uncertainty in a voice that still sounds like leadership, not like cover.","task":"Write the 2-sentence answer that is both calibrated and commanding.","tips":["Lead with your confidence level as a statement: 'I expect yes — here's my basis.'","Name the one variable that could move it, and your trigger for reporting back.","Calibration delivered firmly reads as competence; delivered timidly it reads as doubt."],"focus":["precision","impact"],"placeholder":"I expect yes: the pilot ran at 26 days. The risk is winter volume, and if January exceeds"},
    {"id":"presence-gov-senior-18","level":"senior","profession":"publicservice","title":"Interrupted by the chair","scenario":"Ninety seconds into your answer, the committee chair cuts across you with a new question. Capitulating instantly looks weak; bulldozing on looks defiant. There's a third move: close your point in one clause, then take the new question.","task":"Draft the spoken pivot: the one-clause close of your point, then the turn to her question.","tips":["'The short version: the fix ships in June — and to your question, Chair...'","Compressing your point into a clause shows command; abandoning it mid-word shows fear.","Never talk over the chair; win the moment with composure, not volume."],"focus":["concision","audience"]},
    {"id":"presence-gov-senior-19","level":"senior","profession":"publicservice","title":"The directive that directs","scenario":"Your memo launching the case-file cleanup 'encourages divisions to prioritize, where feasible, efforts toward' the goal. Nobody will do anything, feasibly or otherwise. You have the authority; the memo just declines to use it.","task":"Rewrite the directive: who does what, by when, reported how.","tips":["Directive verbs: 'will complete,' not 'are encouraged to consider.'","One accountable owner per action, named by role.","Include the reporting mechanism — a directive without follow-up is a suggestion with formatting."],"focus":["clarity","structure"],"placeholder":"Each division director will close or escalate every file older than 180 days by October 31, reporting counts to me monthly."},
    {"id":"presence-gov-senior-20","level":"senior","profession":"publicservice","title":"Recommending into a split council","scenario":"Council is split 5–4 on the shelter siting and both factions want your professional recommendation to arm their side. The temptation is mush that offends no one. Your obligation is a clear professional view, delivered so it serves the institution rather than a faction.","task":"Write the 3-sentence professional recommendation for the public report.","tips":["Ground it in professional criteria — service access, cost, code — not in the politics.","State it unambiguously; a hedged recommendation gets weaponized by both sides.","Note explicitly that the decision, and the weighing of community values, is council's."],"focus":["structure","audience"],"placeholder":"On service access, operating cost, and building condition, the Fourth Street site is the stronger option. My recommendation"},
    {"id":"presence-gov-senior-21","level":"senior","profession":"publicservice","title":"Standing in front of your staff","scenario":"A frontline caseworker followed policy exactly and a case still ended badly; the coverage names her. The reporters want a scapegoat and a policy review. What you say in the next thirty seconds tells your whole workforce whether policy compliance protects them.","task":"Draft the spoken 2-3 sentence statement that backs your employee and owns the policy.","tips":["Say plainly: she followed our policy, and the policy is mine to fix.","Move the review to the policy, explicitly away from the person.","Your staff are the second audience, and the more important one."],"focus":["audience","impact"]},
    {"id":"presence-gov-senior-22","level":"senior","profession":"publicservice","title":"'All options are on the table'","scenario":"Your draft response to the arena deficit says the city is 'considering all options.' It's technically true and completely empty — and it invites every faction to campaign for its favourite option for six weeks. You know which two options are real.","task":"Rewrite the line to name the real options and the decision date.","tips":["Naming the two real options kills the speculation about the other five.","Attach the decision date and forum — it converts drift into process.","Say what is NOT on the table if that's what residents most fear."],"focus":["clarity","precision"],"placeholder":"Two options are under review: a renegotiated operating agreement or a managed closure in 2027. Council decides June 14. Selling"},
    {"id":"presence-gov-senior-23","level":"senior","profession":"publicservice","title":"Jargon is not armor","scenario":"Your testimony draft says the department will 'operationalize a multi-modal service delivery transformation leveraging integrated intake pathways.' Committee members hear jargon as evasion, and the plain version of this sentence is actually impressive.","task":"Rewrite the sentence in plain words a councilmember would quote.","tips":["Say what a resident experiences: one application instead of four.","Plain language sounds more senior, not less — jargon reads as hiding.","If the plain version sounds thin, the problem is the plan, not the wording."],"focus":["clarity","concision"],"placeholder":"Residents will file one application instead of four, and get one answer within 30 days."},
    {"id":"presence-gov-senior-24","level":"senior","profession":"publicservice","title":"Thirty seconds with the mayor","scenario":"The mayor is walking to the podium and asks, over her shoulder, 'Anything I need on the shelter file?' You have thirty seconds of hallway. This is the format where careers quietly compound: one decided update, no wind-up.","task":"Write the spoken 2-sentence hallway brief.","tips":["Lead with the one thing that could reach her podium: new number, new risk, new decision.","Speak in conclusions; she can ask for reasoning if she wants it.","End with 'nothing else needs you today' — closing the loop is the gift."],"focus":["concision","audience"]},
    {"id":"presence-gov-senior-25","level":"senior","profession":"publicservice","title":"The last sentence of testimony","scenario":"Your testimony draft ends with 'and so, in conclusion, we will continue working collaboratively with all stakeholders going forward.' Forty minutes of strong evidence, dissolving into vapor. The last sentence is the one the room walks out holding.","task":"Write the closing 2 sentences that end on your position and the ask.","tips":["Restate the recommendation and the single strongest number, once.","End with what you're asking the committee to do — approval, funding, the vote.","Never end on 'continuing to work' — end on the decision."],"focus":["impact","concision"],"placeholder":"The backlog costs residents 90 days and the fix costs $2M. I'm asking this committee to approve it today."}
  ],
  "answering-under-pressure": [
    {"id":"pressure-gov-senior-01","level":"senior","profession":"publicservice","title":"'Yes or no, Director'","scenario":"A councilmember leans into the microphone: 'Yes or no — did your department know about the contamination before the sale closed?' The true answer is 'partially, and here's what that means.' But leading with the nuance sounds like a dodge.","task":"Draft the spoken answer: the direct yes/no-shaped answer first, then one sentence of the necessary nuance.","tips":["Give the closest honest short answer first: 'Yes, in part.'","Then the one clause that makes it accurate — not three paragraphs of context.","Nuance after a direct answer is precision; nuance instead of one is evasion."],"focus":["clarity","precision"]},
    {"id":"pressure-gov-senior-02","level":"senior","profession":"publicservice","title":"'How much did this cost taxpayers?'","scenario":"At the scrum, a reporter asks what the failed procurement cost taxpayers. You know the number: $1.8M. Your media lines say 'the costs are being assessed as part of our review.' They are not; the review closed Tuesday.","task":"Draft the spoken answer that leads with the number.","tips":["Say the number in the first sentence — it will come out anyway, and later is worse.","Follow with what changed so it can't recur; that's the sentence you want quoted after the number.","An official who volunteers the bad number gets believed on the good ones."],"focus":["clarity","impact"]},
    {"id":"pressure-gov-senior-03","level":"senior","profession":"publicservice","title":"'I don't know' at committee","scenario":"The committee asks how many affected files predate 2020. You genuinely don't know, and guessing under oath-adjacent conditions is how officials end up in follow-up hearings. 'I don't know' said well builds trust; said badly it reads as unprepared.","task":"Write the 2-sentence answer: the honest gap plus the concrete commitment.","tips":["'I don't have that figure' — plainly, without squirming.","Commit to the specific delivery: what, to whom, by when.","Say what you DO know that's adjacent — it shows the gap is narrow, not total."],"focus":["precision","audience"],"placeholder":"I don't have the pre-2020 breakdown with me. I'll table it with the clerk by Thursday — I can tell you the total is 4,100."},
    {"id":"pressure-gov-senior-04","level":"senior","profession":"publicservice","title":"The loaded premise","scenario":"'Given that your department has abandoned rural residents, what do you say to families in the valley?' Answering the question as asked accepts 'abandoned.' Attacking the reporter accepts the fight. The move is to replace the premise in one calm clause and answer the real question.","task":"Draft the spoken answer that resets the premise without sounding defensive.","tips":["Correct the premise with a fact, not an adjective: 'We run six clinics in the valley.'","Then answer the legitimate question underneath — service levels are a fair topic.","Never repeat the hostile word, even to deny it; 'we haven't abandoned anyone' is the headline you fear."],"focus":["precision","audience"]},
    {"id":"pressure-gov-senior-05","level":"senior","profession":"publicservice","title":"The resident who's been on hold for a year","scenario":"At the town hall, a man stands up shaking: his accessibility renovation permit has been in review for eleven months, and he names the dates. The room is with him. Whatever you say next is the answer two hundred people take home about whether government listens.","task":"Draft your spoken response: acknowledgment, the honest answer, and the specific follow-up.","tips":["Answer HIS case first — 'eleven months is wrong, and I'll have an answer for you this week' — before any system talk.","Do not explain the backlog to a man living inside it; fix his instance, then address the pattern.","Make the commitment checkable: name who will call him and when."],"focus":["audience","impact"]},
    {"id":"pressure-gov-senior-06","level":"senior","profession":"publicservice","title":"'So you failed?'","scenario":"The auditor general found your division missed its own inspection targets two years running, and the reporter distills it: 'So your department failed — yes?' Agreeing wholesale writes the headline; disputing the audit writes a worse one.","task":"Draft the 2-sentence spoken answer that owns the finding at its actual size.","tips":["Concede the specific finding precisely: 'We missed the target — 71% against 90.'","Size it honestly rather than accepting 'failed' as a blanket: say what didn't fail.","Pivot once to the corrective action with its date, then stop talking."],"focus":["precision","impact"]},
    {"id":"pressure-gov-senior-07","level":"senior","profession":"publicservice","title":"The four-part question","scenario":"A committee member unloads: why did costs rise, who approved the change order, when did you know, and will anyone be disciplined? Answering in a blur lets her claim you skipped one. Answering with structure turns her barrage into your outline.","task":"Write the spoken answer's skeleton: the enumeration sentence plus a one-line answer to each part.","tips":["Play it back first: 'Four questions — costs, approval, timing, discipline. In order:'","Answer each in one sentence before elaborating on any.","Structure under fire reads as unshakeable; it also proves you actually listened."],"focus":["structure","clarity"],"placeholder":"That's four questions — costs, approval, timing, and discipline. In order: costs rose $400K on steel;"},
    {"id":"pressure-gov-senior-08","level":"senior","profession":"publicservice","title":"Outside your file","scenario":"Mid-scrum about your road project, a reporter pivots: 'While you're here — is the city going to settle the police lawsuit?' Not your file, not your place. But 'no comment' sounds like you're hiding something you don't even possess.","task":"Draft the one-sentence spoken deferral that is honest, unbothered, and closes the topic.","tips":["Own the boundary without apology: 'That's not my file, and I won't guess at someone else's.'","Redirect to the right source by name or office.","Then bridge back to your topic in the same breath — leaving a vacuum invites a follow-up."],"focus":["concision","audience"]},
    {"id":"pressure-gov-senior-09","level":"senior","profession":"publicservice","title":"Challenged across the table","scenario":"In front of forty stewards, the union president says your staffing numbers are 'fiction cooked up on the eighth floor.' The room waits. Rising to 'fiction' loses the negotiation; wilting loses the numbers. You need the third voice: level, specific, unmoved.","task":"Draft the spoken response: stand behind the data, offer verification, keep the table.","tips":["Restate the number and its source without heat: payroll records, not projections.","Offer the audit trail: 'Bring your analyst; we'll walk the raw data together Thursday.'","Answer the substance, ignore the theatre — the stewards notice who stayed calm."],"focus":["precision","audience"]},
    {"id":"pressure-gov-senior-10","level":"senior","profession":"publicservice","title":"Your own quote, read back","scenario":"'In 2023 you stood here and said the system upgrade would come in under $4M. It's at $6.2M. Were you wrong then or are you wrong now?' The old quote is real. Reconciling it honestly, on the record, in under thirty seconds, is the whole exam.","task":"Write the 2-3 sentence spoken answer that reconciles the two numbers without weaseling.","tips":["Own the old number as what you believed and why: 'That was the estimate before the security mandate.'","Name precisely what changed and its cost — the delta is your answer.","Don't relitigate the question's framing; reconcile and move to the current plan."],"focus":["precision","structure"],"placeholder":"I said $4M and I believed it — that was before the provincial security mandate added $1.9M in requirements."},
    {"id":"pressure-gov-senior-11","level":"senior","profession":"publicservice","title":"'Will anyone be fired?'","scenario":"After the grant-fraud story, the first question is personnel: 'Will anyone lose their job over this?' You can't discuss individual discipline, and 'I can't comment on personnel matters' — while true — has become a national punchline for cover-ups.","task":"Draft the spoken answer that honors the confidentiality without sounding like a shield.","tips":["Say what process IS underway and what outcomes it can produce, including termination.","Explain in one clause why individual cases stay confidential — it protects due process, not the department.","Commit to reporting the outcome category when it concludes; that's the accountability the public actually needs."],"focus":["clarity","audience"]},
    {"id":"pressure-gov-senior-12","level":"senior","profession":"publicservice","title":"The wall you can name","scenario":"The matter is before the courts, and the committee knows it — but a member asks for details anyway, betting that 'I can't discuss it' will look evasive on the clip. The counter is to be expansive about the boundary itself: what you can't say, why, and when that changes.","task":"Write the 2-sentence answer that makes the legal constraint transparent instead of convenient.","tips":["Name the specific constraint: 'The matter is before the Superior Court; evidence I discuss here can prejudice it.'","Say when you can answer — after judgment, after the settlement — and volunteer to return.","Then answer everything adjacent that is NOT constrained; generosity at the edges proves the wall is real."],"focus":["precision","clarity"],"placeholder":"That matter is before the courts, and anything I say here can prejudice it — I'll answer fully once judgment"},
    {"id":"pressure-gov-senior-13","level":"senior","profession":"publicservice","title":"The same question, fourth time","scenario":"The reporter has asked the same question four ways, hunting for a fifth version of your answer to cut against the first. Robotic repetition looks scripted; four different answers is four headlines. You need the same substance in a human voice.","task":"Draft two spoken variants of your core answer — same facts, different words, no new ground.","tips":["Fix the facts and the commitment; vary only the phrasing.","Acknowledge the repetition once, pleasantly: 'Same answer, and I'll give it as often as asked.'","Never add detail just to escape the loop — that detail is the story they were fishing for."],"focus":["concision","precision"]},
    {"id":"pressure-gov-senior-14","level":"senior","profession":"publicservice","title":"'Why should anyone trust you?'","scenario":"After the privacy breach, a town-hall resident asks the question under all the questions: 'Why should we trust a word you say?' There's no statistic for this one. Defensiveness confirms the distrust; a plea for trust is worthless. Only verifiable commitments buy anything back.","task":"Draft the spoken 3-sentence answer built on checkable actions, not appeals.","tips":["Don't ask for trust — offer verification: published timelines, an external reviewer, a named report date.","Acknowledge the breach earned the question; that acknowledgment is the only opening the room will accept.","Small kept promises are the currency; name the first one and its date."],"focus":["audience","impact"]},
    {"id":"pressure-gov-senior-15","level":"senior","profession":"publicservice","title":"Correcting the councilmember's number","scenario":"A councilmember builds her attack on the claim that your department returned $8M unspent. The real figure is $800K. She's wrong by 10x, on camera, and how you correct her decides whether the story is her error or your arrogance.","task":"Draft the spoken correction that fixes the record without scoring the point.","tips":["Correct the number, not the person: 'The figure in the report is $800,000.'","Offer the source page so the correction is checkable, not competitive.","Skip any tone of victory — the moment she looks foolish, you've made an enemy of the swing vote."],"focus":["precision","audience"]},
    {"id":"pressure-gov-senior-16","level":"senior","profession":"publicservice","title":"The hypothetical trap","scenario":"'If the province cuts your funding next year, which programs will you axe first?' Any program you name becomes tomorrow's 'DEPARTMENT EYES CUTS TO X' headline, terrifying that program's clients over a cut that may never come. But 'I won't deal in hypotheticals' is a cliché that reads as dodge.","task":"Draft the spoken answer that declines the specifics but answers the principle.","tips":["Answer the real underlying question: how you would decide, not what you would cut.","Name your decision criteria — statutory obligations first, direct services last.","Explain in one clause why naming programs now would cause real harm; that's the honest reason, so give it."],"focus":["structure","audience"]},
    {"id":"pressure-gov-senior-17","level":"senior","profession":"publicservice","title":"Ten minutes becomes ninety seconds","scenario":"The committee is running long and the chair announces your ten-minute slot is now 'a couple of minutes, please.' Your team's carefully sequenced deck is dead. What survives is whatever you can say, cold, in ninety seconds, and it has to include the ask.","task":"Write the 90-second spoken version: situation, evidence, ask.","tips":["Cut to one number, one consequence, one ask — the rest goes to the written record.","Say the ask twice: opening and closing.","Compression under pressure, done gracefully, impresses committees more than the full deck ever would."],"focus":["concision","impact"]},
    {"id":"pressure-gov-senior-18","level":"senior","profession":"publicservice","title":"The question from grief","scenario":"At the public meeting after the crosswalk death, the victim's sister asks why the intersection her family flagged two years ago was never upgraded. She is not a stakeholder to be managed; she's right, and she's grieving, and the room knows both. Process language here is a second injury.","task":"Draft your spoken response: human first, honest about the failure, concrete about what changes.","tips":["Answer her as a person before answering as an institution — say her brother's name if she shared it.","Do not explain the prioritization matrix; say plainly the request wasn't acted on and that's the failure.","Commit to the specific change and date; a grieving family can carry a date, not a framework."],"focus":["audience","impact"]},
    {"id":"pressure-gov-senior-19","level":"senior","profession":"publicservice","title":"'Whose decision was it?'","scenario":"The committee wants a name: who decided to waive the second inspection? The decision was recommended by a manager, endorsed by a director, signed by you. Naming the manager is throwing her to the wolves; refusing all names is a cover-up. The truthful shape is the chain, ending at you.","task":"Write the 2-sentence answer that gives the decision chain and lands the accountability on yourself.","tips":["Describe the chain by role, not personality — recommendation, endorsement, approval.","End the chain where it truly ends: your signature, your accountability.","Protecting your staff from the mob is not the same as hiding the process; give the process, keep the person."],"focus":["clarity","structure"],"placeholder":"The waiver was recommended at the branch level and approved by me — the signature is mine, and so is the accountability."},
    {"id":"pressure-gov-senior-20","level":"senior","profession":"publicservice","title":"The number you must estimate live","scenario":"Council asks, mid-debate, roughly what a one-year delay would cost. No note exists. Refusing any figure stalls the debate on your silence; a naked guess becomes a fact with your name on it. The professional move is a bounded estimate with its basis stated aloud.","task":"Draft the spoken bounded estimate: range, basis, and the commitment to confirm.","tips":["Give a range with its logic shown: 'Escalation runs 4-6% on this class of work, so roughly $2-3M.'","Label it out loud: 'a rough order of magnitude, to be confirmed in writing.'","Send the confirmed figure within 48 hours — the follow-through is what licenses the next live estimate."],"focus":["precision","structure"],"placeholder":"Rough order of magnitude: construction escalation runs 4-6% annually on this class of work, so a one-year delay costs $2-3M."},
    {"id":"pressure-gov-senior-21","level":"senior","profession":"publicservice","title":"'It's in the brief' is not an answer","scenario":"A committee member asks a question answered on page 3 of the brief you tabled. Saying 'as noted in our submission' scores a point and loses a vote. The members who didn't read it are your audience too — maybe especially.","task":"Draft the spoken answer that gives the substance fresh, as if for the first time.","tips":["Answer fully, warmly, with zero reference to the document — nobody has ever been persuaded by 'as I wrote.'","Treat the repeat as a gift: a second chance to deliver your best point aloud, on the record.","If anything, sharpen it: the spoken version can be better than page 3."],"focus":["audience","clarity"]},
    {"id":"pressure-gov-senior-22","level":"senior","profession":"publicservice","title":"Ambushed in the parking lot","scenario":"A camera crew is waiting by your car with questions about the memo leaked an hour ago. You haven't read the story. Walking away in silence is the B-roll of guilt; answering blind is malpractice. There is a third option, and it's about four sentences long.","task":"Draft the spoken holding response: composed, honest about the timing, committed to a real follow-up.","tips":["Say the true thing: 'The story is an hour old and I won't respond to a document I haven't reviewed.'","Give the concrete follow-up: statement by 5 p.m., through the press office.","Stop walking while you say it — thirty seconds of composure on camera beats a fleeing back."],"focus":["concision","audience"]},
    {"id":"pressure-gov-senior-23","level":"senior","profession":"publicservice","title":"Defending your team without defensiveness","scenario":"A councilmember calls your permitting staff 'either lazy or incompetent.' Heat rises in your chest — these are people who worked weekends all winter. But anger validates the attack, and silence abandons your staff. The answer is facts delivered with visible calm and a boundary drawn once.","task":"Draft the spoken response: the boundary, the facts, and the redirect to the real issue.","tips":["Draw the line without matching the heat: 'I won't accept that characterization of my staff.'","Then the numbers: volumes up 40%, headcount flat — the system is the story, not the people.","Redirect to what would actually fix it; make the attacker choose between helping and grandstanding."],"focus":["audience","impact"]},
    {"id":"pressure-gov-senior-24","level":"senior","profession":"publicservice","title":"When the honest answer helps your critic","scenario":"The advocacy group's leader asks, on camera, whether the wait-list has grown since last year. It has — 15% — and she'll use your answer in her campaign against your department. The temptation to blur the number is enormous, and fatal: she has the FOI response already.","task":"Write the 2-sentence spoken answer that gives the true number and your frame in the same breath.","tips":["Say the number cleanly; being sourced by your critics is better than being caught by them.","Attach your frame immediately: cause and response, one sentence, no excuses dressed as context.","Credibility is the long game — the official who concedes true bad numbers owns the debate's facts."],"focus":["precision","impact"],"placeholder":"Yes — the wait-list grew 15% this year. Referrals rose 30% while our funding stayed flat, which is exactly why"},
    {"id":"pressure-gov-senior-25","level":"senior","profession":"publicservice","title":"Correcting yourself, mid-hearing","scenario":"Twenty minutes ago you told the committee the pilot ran in four sites. Reviewing your notes during a lull, you see it: three sites. Nobody caught it. You can let it ride and risk the transcript, or take the microphone and fix your own error in front of everyone.","task":"Draft the spoken self-correction: brief, unprompted, and unflustered.","tips":["Ask the chair for the floor and correct in one sentence: 'Earlier I said four sites; the correct number is three.'","No elaborate apology — brisk correction reads as integrity, grovelling reads as weakness.","Do it in the same session; a correction letter next week looks like you hoped no one noticed."],"focus":["precision","concision"]}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-gov-senior-01","level":"senior","profession":"publicservice","title":"The budget ask as a before/after","scenario":"Your transit reliability request reads as a list of costs: $4.2M for spare buses, mechanics, and parts inventory. Council sees a bill. The persuasive version is a change story: what riders live with now, what changes, and the bridge between.","task":"Write the 3-sentence before/after framing for the council report.","tips":["Before: the missed shift, the stranded rider — in concrete resident terms.","After: the specific experience that improves, with the number attached.","The $4.2M is the bridge, introduced last, after the destination is worth it."],"focus":["structure","impact"],"placeholder":"Today, one bus in eleven never shows, and the rider waiting for it is late for a shift she can't afford to miss."},
    {"id":"narrative-gov-senior-02","level":"senior","profession":"publicservice","title":"One resident, then the number","scenario":"Your homelessness report opens with the count: 1,340 people on the by-name list. Accurate, and numbing — council has heard four-digit numbers for years. Data informs; a person persuades. The craft is pairing one true story with the number so each carries the other.","task":"Write the report's opening 3 sentences: one resident's situation, then the count it represents.","tips":["Choose a real, permissioned story with one concrete detail — the detail does the work.","Land the statistic immediately after: 'He is one of 1,340.'","One story is a window; two is a slideshow. Stop at one."],"focus":["audience","impact"],"placeholder":"Raymond, 58, worked at the mill for thirty years and has slept in his car since his rent doubled in March. He is one of 1,340"},
    {"id":"narrative-gov-senior-03","level":"senior","profession":"publicservice","title":"Answering 'we can't afford it' first","scenario":"Your early-intervention proposal will die on four words: 'we can't afford it.' You know the objection is coming — the same councilmember says it every cycle. The strongest move is to raise it yourself, steelman it, and answer it before he gets to the microphone.","task":"Write the objection-and-answer paragraph for the report.","tips":["State his objection at full strength — a weak version insults him and persuades nobody.","Answer with the cost of NOT acting: the downstream numbers, sourced.","Naming the objection first converts an ambush into your best paragraph."],"focus":["structure","precision"],"placeholder":"The fair objection is that $3M is unaffordable this cycle. But we are already paying more than that:"},
    {"id":"narrative-gov-senior-04","level":"senior","profession":"publicservice","title":"The reorg as a story staff can join","scenario":"The restructuring memo to staff is all boxes and reporting lines. Staff read reorg memos asking one question — what happens to me — and join or resist based on whether the story has a place for them. Right now your memo has an org chart where the story should be.","task":"Write the memo's opening 3 sentences: where we are, where we're going, and what it makes possible for the people doing the work.","tips":["Name the frustration staff already feel — the story starts where they are, not where the chart is.","Describe the after in terms of their workday, not the org design.","People don't resist change; they resist loss. Say plainly what is not being lost."],"focus":["audience","structure"],"placeholder":"Today a caseworker who spots a housing problem has to send her client to a different office and hope. Starting"},
    {"id":"narrative-gov-senior-05","level":"senior","profession":"publicservice","title":"Selling the invisible win","scenario":"Nothing happened this year: no watermain failures, no boil-water days, no flooded basements. That's the product of the maintenance budget you're defending — and it's invisible. Cut-year logic says 'nothing broke, so we can spend less.' Your narrative has to make the non-event vivid.","task":"Write the 3-sentence defense that makes prevention concrete.","tips":["Give the counterfactual a body: name the last failure year and what it cost, in dollars and boil-water days.","Use the near-misses: the 14 pipes replaced this year that were one winter from bursting.","'Nothing happened' is the deliverable — say that sentence explicitly and proudly."],"focus":["impact","precision"],"placeholder":"In 2019 we deferred this exact budget line, and the February watermain failure cost $4M and six boil-water days. This year"},
    {"id":"narrative-gov-senior-06","level":"senior","profession":"publicservice","title":"From data dump to decision story","scenario":"Your staff's climate-adaptation report gives council 60 pages of flood mapping, projections, and scenario tables. It's rigorous and it moves no one. Council doesn't need to absorb the data; they need to see the decision the data points to, framed as a choice with consequences.","task":"Write the 3-sentence decision framing that would open the report.","tips":["Compress the analysis to one stark comparison: cost to protect now vs. cost to repair later.","Frame it as the choice council is actually making by deciding or deferring.","The 60 pages become the appendix that proves the three sentences."],"focus":["structure","clarity"],"placeholder":"Council has one decision in this report: spend $18M over five years on flood protection, or accept modeled damages of"},
    {"id":"narrative-gov-senior-07","level":"senior","profession":"publicservice","title":"The minister's frame, not yours","scenario":"You need the minister to champion the service-modernization funding. Your draft argues from your department's pain: legacy systems, staff burnout, audit findings. Her mandate letter is about affordability and rural access. The facts are yours; the frame has to be hers.","task":"Rewrite the pitch's opening 2 sentences in the minister's priority language.","tips":["Open inside her mandate: what this does for affordability, for rural residents.","Your operational pain appears only as it threatens her outcomes.","Persuasion at this level is translation — same proposal, the decider's dialect."],"focus":["audience","impact"],"placeholder":"This investment cuts the cost of processing a claim by 60% and lets rural residents complete every service online —"},
    {"id":"narrative-gov-senior-08","level":"senior","profession":"publicservice","title":"The shelter siting and the fear underneath","scenario":"The neighbourhood meeting about the supportive-housing site will be packed and hostile. The residents' stated objections are parking and property values; the real one is fear. A narrative that answers only the stated objections leaves the actual one untouched and the room unmoved.","task":"Draft your spoken 3-4 sentence framing that names the fear respectfully and answers it with evidence.","tips":["Say the quiet part with respect: 'The real question is whether this makes your street less safe.'","Answer with the evidence from the two sites already operating: calls for service, incidents, before and after.","Give residents a role in the after — a liaison committee with teeth is narrative, not concession."],"focus":["audience","structure"]},
    {"id":"narrative-gov-senior-09","level":"senior","profession":"publicservice","title":"The grant narrative that moves reviewers","scenario":"Your federal application's narrative section lists program activities: workshops delivered, partnerships formed, referrals made. Reviewers fund change, not activity. The winning narratives all have the same skeleton: here's the stuck problem, here's our different approach, here's the change we can prove.","task":"Rewrite the narrative's opening 3 sentences on that skeleton.","tips":["Open with the problem's stubbornness: what stayed broken despite existing services.","Your approach earns one sentence — the mechanism, not the activity list.","Close the opening with the provable change and its measure."],"focus":["structure","impact"],"placeholder":"Youth unemployment in the north end has held above 20% for a decade despite three employment programs, because none"},
    {"id":"narrative-gov-senior-10","level":"senior","profession":"publicservice","title":"Sunsetting the beloved program","scenario":"The community garden grants program is adored, photographed, and — per the evaluation — reaches 200 households at a cost that could house 40 people. Killing it takes more than data; the people who love it aren't wrong to love it. The persuasion is a better after, honestly compared.","task":"Write the 3-sentence case that honors what the program was and makes the trade concrete.","tips":["Start by crediting what it genuinely did — persuasion that trashes the beloved thing loses the room.","Make the trade-off explicit and human on both sides: 200 gardeners, 40 people housed.","Offer the remnant: what survives in another form, so the loss isn't total."],"focus":["audience","impact"],"placeholder":"The garden grants built real community for 200 households, and that matters. But the same $600K houses 40 people"},
    {"id":"narrative-gov-senior-11","level":"senior","profession":"publicservice","title":"The op-ed with an arc","scenario":"The department head asked you to draft an op-ed defending the new stormwater fee. Your draft is a rebuttal — point by point against the critics. Rebuttals persuade nobody; they re-air the criticism. An op-ed needs its own arc: a scene, a stake, a turn, an ask.","task":"Write the op-ed's opening 3 sentences: scene first, thesis second.","tips":["Open in a basement, not in a policy: the June flood, the specific street.","Let the thesis arrive as the scene's meaning, not as a press line.","Never quote the critics; write the piece they'll have to respond to."],"focus":["impact","audience"],"placeholder":"On June 14, forty basements on Maple Street filled with a metre of stormwater in twenty minutes. The pipes under"},
    {"id":"narrative-gov-senior-12","level":"senior","profession":"publicservice","title":"The union's before/after, not yours","scenario":"You need the union to accept flexible scheduling for the new extended service hours. Your draft sells management's story: coverage, efficiency, service standards. Across the table, those words mean 'lose your weekends.' The persuasive version is built from their before and after.","task":"Write the 3-sentence framing you would open the bargaining session with, in the members' terms.","tips":["Their before: forced overtime with 48 hours' notice — name the pain they already have.","Their after: what members gain — predictable rotations, premium bands, first pick by seniority.","Efficiency arguments persuade arbitrators, not members; save them for the brief."],"focus":["audience","structure"]},
    {"id":"narrative-gov-senior-13","level":"senior","profession":"publicservice","title":"Pitching the rival municipality","scenario":"The regional transit integration only works if the neighbouring city joins, and their council reflexively distrusts anything yours proposes. A pitch about regional efficiency will be heard as 'help pay for their system.' Your narrative must make them the protagonist, provably.","task":"Write the 2-3 sentence pitch framed entirely around their riders and their council's wins.","tips":["Their riders' before/after first: the double fare, the 40-minute transfer, gone.","Show their leverage plainly: what they get that they couldn't build alone.","Give their council the headline moment — persuasion across a rivalry runs on credit-sharing."],"focus":["audience","impact"],"placeholder":"Your riders currently pay two fares and wait 40 minutes to cross the boundary. Under integration, one fare"},
    {"id":"narrative-gov-senior-14","level":"senior","profession":"publicservice","title":"The audit as origin story","scenario":"The auditor's report on your permitting division is brutal, public, and accurate. You can absorb it as a wound or claim it as a mandate. The difference is narrative: the same findings, reframed as chapter one of the reform you're now announcing — with the humility that keeps it credible.","task":"Write the 3-sentence public framing that turns the findings into the case for your reform plan.","tips":["Accept the findings without qualification in sentence one — any hedging kills the reframe.","Position the audit as the diagnosis your plan treats, point by point.","Announce one visible change with a date; a narrative needs a first scene, not just a moral."],"focus":["structure","impact"],"placeholder":"The auditor is right: our permitting system fails the people it exists to serve. Her report is now our"},
    {"id":"narrative-gov-senior-15","level":"senior","profession":"publicservice","title":"'Why now' without alarm bells","scenario":"The dam safety upgrades have been deferrable for a decade, which is exactly why they've been deferred. Your report must make this the year — real urgency, honestly sourced — without the manufactured-crisis tone that councils have learned to discount.","task":"Write the 2-3 sentence 'why now' paragraph.","tips":["Anchor urgency in a dated fact: the 2026 inspection downgrade, the insurer's letter, the closing grant window.","Show the cost curve: what a year of waiting adds, in dollars.","One honest urgency beats three inflated ones — councils punish crying wolf for a generation."],"focus":["precision","impact"],"placeholder":"Three things changed this year: the inspection downgraded the spillway to 'poor,' our insurer flagged it, and the federal"},
    {"id":"narrative-gov-senior-16","level":"senior","profession":"publicservice","title":"The analogy that carries the policy","scenario":"The stormwater utility fee is dying in public debate because it sounds like 'a tax on rain.' Complex cost-allocation logic won't survive a scrum. What survives is an analogy: one comparison that makes the fee's fairness obvious in a sentence.","task":"Write the 1-2 sentence analogy you would use at the podium, then the follow-up fact.","tips":["Ground it in something residents already pay by use: the more you pave, the more runoff you send, the more you pay.","Test the analogy for the counterattack — a good one survives its own extension.","Follow the analogy with one number, so the charm has a spine."],"focus":["clarity","audience"],"placeholder":"It works like your water bill in reverse: the more pavement sends runoff into our pipes, the more of the pipe"},
    {"id":"narrative-gov-senior-17","level":"senior","profession":"publicservice","title":"Persuading peers you can't direct","scenario":"The integrated youth-services plan needs three other departments to reassign staff you have no authority over. Your memo can't instruct; it must recruit. Peer persuasion runs on a different fuel: their mandates advanced, their risks named, their fingerprints on the design.","task":"Write the 2-3 sentence pitch to a peer director in terms of her mandate and her win.","tips":["Open with her problem, not your plan — the referral backlog her division wears.","Show her fingerprints: what her team shapes, what carries her division's name.","Name the cost you're NOT asking her to bear; peers listen for the hidden invoice."],"focus":["audience","structure"],"placeholder":"Your intake team spends a third of its time on youth files that bounce between our departments. This design"},
    {"id":"narrative-gov-senior-18","level":"senior","profession":"publicservice","title":"The speech that moves a referendum","scenario":"The recreation bond goes to voters in six weeks, and you have eight minutes at the community association. Referenda aren't won by facility specs; they're won when voters can see a specific Tuesday evening in the building that doesn't exist yet.","task":"Draft the spoken opening 3 sentences that put the audience inside the after.","tips":["Paint one scene with people in it — the Tuesday swim lesson, the seniors' league — before any number.","Then the number that makes it real: cost per household per month, in coffee terms.","End the opening with who decides: 'This exists if you vote for it.' Voters move when they're the protagonist."],"focus":["impact","audience"]},
    {"id":"narrative-gov-senior-19","level":"senior","profession":"publicservice","title":"Steelman on paper","scenario":"Your cabinet submission for the procurement reform will face one serious objection: it concentrates authority in fewer hands, and the last concentration of authority produced the scandal of 2021. If the submission doesn't raise this itself, the deputy ministers' committee will — fatally.","task":"Write the objection paragraph: the strongest version of the concern, then your answer.","tips":["Write the objection so well its owner would sign it — anything less looks like you didn't understand it.","Answer with design, not assurance: the specific controls that make this concentration different.","Placing the objection prominently signals confidence; burying it signals fear."],"focus":["structure","precision"],"placeholder":"The strongest objection to this design is concentration risk: fewer approvers failed us in 2021. Three controls distinguish"},
    {"id":"narrative-gov-senior-20","level":"senior","profession":"publicservice","title":"Recruiting the skeptical graduate","scenario":"You're speaking to a university class where 'government job' means slow, beige, and bureaucratic. Your recruiting slides list benefits and pension tiers. Nobody at 24 is moved by pension tiers. What they're starving for is scale and meaning — which you have and the private sector can't match.","task":"Draft the spoken 3-sentence pitch built on scale of impact, not security.","tips":["Lead with scale: the decision you made at 31 that touched 200,000 people.","Be honest about the frustrations — candor is the credibility this audience runs on.","One true story of a real civil servant's Tuesday beats every benefits slide."],"focus":["audience","impact"]},
    {"id":"narrative-gov-senior-21","level":"senior","profession":"publicservice","title":"Pilot to permanent","scenario":"The mobile crisis team pilot worked: 2,000 calls diverted, zero injuries, ER visits down. Now you're asking council to fund it permanently at triple the budget, and 'the pilot went well' isn't a story — it's a grade. The persuasive frame is what the city has already become, and what reversing it would mean.","task":"Write the 3-sentence case that frames permanence as continuation, not expansion.","tips":["Frame the after as already here: this is how the city responds to crisis now.","Make the alternative vivid: cancelling means 2,000 calls a year go back to armed response.","Loss aversion beats gain framing — protect what works, don't pitch what might."],"focus":["impact","structure"],"placeholder":"For eighteen months, a person in crisis in this city has been met by a nurse and a counsellor — 2,000 times, without"},
    {"id":"narrative-gov-senior-22","level":"senior","profession":"publicservice","title":"Investment framing, honestly earned","scenario":"Comms wants every expense called an 'investment.' The word is so overused it now signals spin. The retrofit program actually is one — it returns measurable savings — and your job is to make the word land by showing the arithmetic instead of asserting the label.","task":"Write the 2-sentence framing that earns 'investment' with the payback math.","tips":["Show the return: $9M spent, $1.4M/year saved, payback in seven years — then the word is just accurate.","If a spend has no measurable return, don't call it an investment; call it what it is and defend it as that.","The arithmetic is the persuasion; the label is only the caption."],"focus":["precision","impact"],"placeholder":"The $9M retrofit cuts our energy costs by $1.4M a year — it repays itself in seven years and saves every year after."},
    {"id":"narrative-gov-senior-23","level":"senior","profession":"publicservice","title":"From stakes to ask at the town hall","scenario":"You've spent twenty minutes at the town hall explaining why the water rates must rise: the pipes, the deferrals, the risk. Heads are nodding. And then your draft ends with 'thank you for your time.' You built the stakes and forgot the bridge — what you're actually asking of the room.","task":"Write the closing 2-3 sentences that convert the stakes into a specific ask.","tips":["Name the ask precisely: support the phased option at Thursday's council meeting, in person or in writing.","Connect it back to the stakes in one clause — the bridge is one sentence long.","People leave meetings willing to act and not knowing how; the how is your job."],"focus":["impact","clarity"],"placeholder":"If you can live with $9 a month to never live through 2019's boil-water summer again, council needs to hear it Thursday."},
    {"id":"narrative-gov-senior-24","level":"senior","profession":"publicservice","title":"The mandate letter, translated for staff","scenario":"The minister's new mandate letter is 14 bullet points of government priorities. Forwarded raw to your branch, it will read as more work from above. Translated, it could be the story of why this branch matters this year. Same letter; the difference is narrative.","task":"Write the 3-sentence staff message that turns the mandate into your branch's mission.","tips":["Pick the two bullets your branch actually owns and name them as yours.","Connect each to work staff already do — the story is continuation and recognition, not new orders.","End with what success looks like in a year, concretely, so the mission has a finish line."],"focus":["audience","structure"],"placeholder":"Two lines in the minister's mandate letter belong to this branch: cutting licensing times in half, and taking every service"},
    {"id":"narrative-gov-senior-25","level":"senior","profession":"publicservice","title":"Ending on the ask","scenario":"Your ten-minute pitch to the regional board lands every point, and then the final slide says 'Questions?' A persuasive presentation that ends without an ask is a documentary. The last thirty seconds exist for one sentence: exactly what you want, from whom, by when.","task":"Write the closing 2 sentences: the ask, stated twice in different sizes.","tips":["The full ask first: approve the $1.2M regional share at the March meeting.","Then the small version — the yes they can give today: 'a motion to receive the plan and direct staff to draft the agreement.'","Silence after the ask; the next voice should be theirs."],"focus":["impact","concision"],"placeholder":"I'm asking this board to approve the $1.2M regional share at the March meeting. Today, the step is a motion directing"}
  ],
  "delivering-hard-messages": [
    {"id":"hard-gov-senior-01","level":"senior","profession":"publicservice","title":"The program closure, said first","scenario":"The adult literacy program closes in September, and your announcement draft spends two paragraphs on the department's commitment to lifelong learning before the word 'closure' appears. Participants will read the first line, feel reassured, and be blindsided in paragraph three.","task":"Rewrite the announcement's first 2 sentences: the closure, the date, and what happens to current participants.","tips":["The hard fact goes in sentence one — burying it converts sadness into betrayal.","Sentence two is the reader's next question: what happens to me, specifically.","Cut every commitment-to-values phrase; they read as the sound of a door closing."],"focus":["clarity","structure"],"placeholder":"The adult literacy program will close on September 30. Every current participant will be offered a transfer to"},
    {"id":"hard-gov-senior-02","level":"senior","profession":"publicservice","title":"Sixty positions, said to their faces","scenario":"Budget reductions eliminate sixty positions, and you're announcing it at an all-staff meeting rather than by memo — the right call, and the harder one. The room will remember your first thirty seconds forever. A cushioned wind-up means sixty people hear their fate through a fog of dread.","task":"Draft your spoken opening 3 sentences.","tips":["Say it in the first sentence: how many positions, effective when.","Then immediately: how people will find out individually, and by what date certainty arrives.","Do not say 'this is hard for me too' — your difficulty is not the room's concern today."],"focus":["clarity","audience"]},
    {"id":"hard-gov-senior-03","level":"senior","profession":"publicservice","title":"No to the councilmember's project","scenario":"A councilmember wants her ward's splash pad in this year's capital plan. It scored 14th of 30 on the criteria council itself adopted, and the line is drawn at 10. She will hear 'no' as a personal slight unless the no arrives clean, reasoned, and with the path that isn't a false promise.","task":"Write the 3-sentence response: the no, the criteria, and the honest path.","tips":["'No for this cycle' in sentence one — a no that takes three paragraphs to arrive breeds resentment, not respect.","Cite the ranking and the council-adopted criteria; the process is your shelter and hers.","Offer only what's real: what would change its score, not vague hope."],"focus":["clarity","structure"],"placeholder":"The splash pad won't be in this year's plan: it ranked 14th of 30 under council's criteria, and the line is 10. What would"},
    {"id":"hard-gov-senior-04","level":"senior","profession":"publicservice","title":"Telling the minister the date is gone","scenario":"The minister announced the portal launch for March. It will not be ready until June, and you've known for a week. Every day of delay in telling her converts a project slip into a trust breach. The briefing must lead with the miss, own it, and hand her the decision she now faces.","task":"Write the briefing note's opening 3 sentences.","tips":["Sentence one: the March date will be missed; the achievable date is June 10.","One sentence of cause — the true one, not the flattering one.","Frame her choice: announce the revision now, or hold for the recovery plan Friday. Recommend one."],"focus":["clarity","impact"],"placeholder":"The portal will not launch in March; the achievable date is June 10. Integration testing surfaced failures in"},
    {"id":"hard-gov-senior-05","level":"senior","profession":"publicservice","title":"The advisory that won't end yet","scenario":"Residents expected the boil-water advisory lifted today; testing says two more weeks. Frustration is high and the draft notice hides the extension under a recap of the treatment process. Bad news delivered vaguely gets read twice and trusted half as much.","task":"Write the public notice's first 2 sentences.","tips":["Extension and new date first: two more weeks, lifted on or about the 18th.","One sentence of why — the specific test result, in plain words.","Resist the urge to pad with reassurance; the accurate date IS the reassurance."],"focus":["clarity","concision"],"placeholder":"The boil-water advisory will remain in place for two more weeks, until approximately October 18. Thursday's samples still show"},
    {"id":"hard-gov-senior-06","level":"senior","profession":"publicservice","title":"Declining the grant application","scenario":"The seniors' association applied for $40K and scored below the funding line. They're volunteers; they spent weeks on the application; the president will read your letter aloud at their meeting. A form rejection insults the effort. A kind rejection is still a rejection in sentence one.","task":"Write the letter's first 3 sentences.","tips":["The decision first, unambiguous — hope deferred by a warm opening is cruelty with manners.","One specific, true sentence about the application's genuine strength.","End with something real: the score, the gap, and the next intake date if reapplying makes sense."],"focus":["audience","clarity"],"placeholder":"Your application was not approved for funding this cycle. The program plan was among the strongest we read; the gap was"},
    {"id":"hard-gov-senior-07","level":"senior","profession":"publicservice","title":"Feedback for the twenty-year manager","scenario":"A manager with twenty years of service is failing at her current role — missed deadlines, a team in quiet revolt. Everyone has been too kind to say it plainly, for years, which is how she got here. The kindest available act is specificity: what, exactly, is not working, and what change is required.","task":"Write the 3 sentences that open the feedback conversation.","tips":["Name the specific pattern with two dated examples — vague feedback is deniable and useless.","Separate the person from the performance explicitly; her service is real and so is the problem.","State what must change and by when, as a requirement, not a wish."],"focus":["precision","audience"],"placeholder":"I need to be direct with you about the last two quarters: the March filing and the audit response both missed"},
    {"id":"hard-gov-senior-08","level":"senior","profession":"publicservice","title":"The benefits reduction, across the table","scenario":"The new fiscal mandate cuts the extended-health subsidy, and you have to say so at the bargaining table — to people who negotiated it, in good faith, a decade ago. Spin will be dismantled in seconds. What survives across a bargaining table is the unvarnished fact and the honest reason.","task":"Draft your spoken 3-sentence opening.","tips":["State the change exactly: what's reduced, by how much, from when.","Give the real reason with its numbers — the mandate, the deficit — not 'sustainability' vapor.","Say what's NOT changing and what's negotiable about implementation; the table needs something to work with."],"focus":["clarity","precision"]},
    {"id":"hard-gov-senior-09","level":"senior","profession":"publicservice","title":"Misconduct, confirmed and said","scenario":"The investigation confirmed a senior employee falsified inspection records. The public statement must say what happened without hiding behind 'personnel matter' — public trust in every honest inspector depends on the department being harder on itself than the press would be.","task":"Write the statement's first 3 sentences.","tips":["Say what was done, plainly: records were falsified, on how many files, over what period.","Say what happened to the individual within what privacy law allows — and don't hide behind it beyond that.","Third sentence: what every affected file gets now. The remedy is the message."],"focus":["clarity","impact"],"placeholder":"An internal investigation has confirmed that inspection records were falsified on 31 files between 2023 and 2025. The employee"},
    {"id":"hard-gov-senior-10","level":"senior","profession":"publicservice","title":"The hole in the budget","scenario":"Nine weeks after council passed the budget, you've found a $2.1M revenue error — your department's error. Council will be angrier about a cover-up than a mistake, but only if the disclosure is fast, complete, and paired with the fix. The memo you write tonight decides which story this becomes.","task":"Write the memo's opening 3 sentences to council.","tips":["The number, the cause, and whose error it was — first sentence, no wind-up.","Distinguish immediately what this does and doesn't affect; panic fills any vacuum you leave.","Close the opening with the fix options and the date you'll bring them."],"focus":["clarity","structure"],"placeholder":"We have found a $2.1M error in the approved budget: transfer revenue was counted twice, and the error was ours."},
    {"id":"hard-gov-senior-11","level":"senior","profession":"publicservice","title":"Telling the mayor to walk it back","scenario":"The mayor announced Friday that the new rink opens in December. It cannot — the slab failed inspection, and December was never real. Someone has to tell her she must correct her own announcement, and that someone is you, in her office, in about an hour.","task":"Draft your spoken 3 sentences: the fact, the exposure, and the recommended correction.","tips":["Lead with the fact and its firmness: December is not achievable under any spend.","Name her exposure honestly — the correction is cheaper now than in November.","Bring the corrected line drafted; never deliver a walk-back without the replacement in hand."],"focus":["clarity","audience"]},
    {"id":"hard-gov-senior-12","level":"senior","profession":"publicservice","title":"Cutting the route people ride","scenario":"Route 9 is being cut, and tonight's town hall is full of the people who ride it. Your slides show system-wide optimization logic. Nobody on Route 9 cares about system-wide logic; they care about Tuesday morning. The hard message has to be delivered in their terms, with the mitigation real.","task":"Draft your spoken opening 3 sentences.","tips":["Say it plainly: Route 9 ends April 30 — the room already knows; dodging insults them.","Give the honest reason in one sentence: 41 riders a day on a route that costs $19 per trip.","Spend the rest on what's real for THEM: the on-demand service, the revised 12, door-to-door for registered riders."],"focus":["audience","impact"]},
    {"id":"hard-gov-senior-13","level":"senior","profession":"publicservice","title":"Non-renewal, without the fog","scenario":"The facilities-maintenance vendor's contract won't be renewed after eight years. Your draft letter is so cushioned — 'evolving service delivery models,' 'strategic realignment' — that the vendor may genuinely not understand they've lost the work. Ambiguity here is not kindness; it's a lawsuit seed.","task":"Rewrite the letter's first 2 sentences.","tips":["Non-renewal and end date in sentence one, in those words.","The reason in plain terms if one can be given; silence beats a euphemism that implies a hidden reason.","State the transition obligations and thank them once, specifically, at the end — not instead of clarity."],"focus":["clarity","precision"],"placeholder":"The facilities maintenance contract will not be renewed when it expires March 31. This decision reflects the results of"},
    {"id":"hard-gov-senior-14","level":"senior","profession":"publicservice","title":"'We got it wrong'","scenario":"For three weeks the department insisted the sinkhole was a private plumbing failure. The engineering review came back yesterday: it was the city's storm sewer. The family you publicly contradicted is owed a correction as loud as the original denial — and your statement is the instrument.","task":"Write the public correction's first 3 sentences.","tips":["'We were wrong' — those words, not 'new information has come to light.'","Name what you now know and correct the specific earlier claim, explicitly.","Say what the family gets and when; a correction without remedy is just a confession."],"focus":["clarity","impact"],"placeholder":"We were wrong. The engineering review confirms the collapse was caused by the city's storm sewer, not by the"},
    {"id":"hard-gov-senior-15","level":"senior","profession":"publicservice","title":"The freeze continues","scenario":"Staff endured a pay freeze last year on the understanding it was temporary. The new fiscal framework extends it another year, and you're writing the message. The draft you inherited opens with three paragraphs about global economic conditions. Nobody's rent is waiting for paragraph four.","task":"Rewrite the opening 2 sentences.","tips":["The extension, stated first, with its end date if one truly exists — and no date if none does.","Acknowledge the broken expectation directly; pretending 'temporary' wasn't said costs more than owning it.","Whatever real thing you CAN offer — the step increases, the leave conversion — say it plainly, without inflating it."],"focus":["clarity","audience"],"placeholder":"The salary freeze will continue through next fiscal year. I know this extends what we all understood to be a one-year"},
    {"id":"hard-gov-senior-16","level":"senior","profession":"publicservice","title":"No, the rules won't bend","scenario":"A resident is asking you — the third person up the chain — to waive the setback requirement for the deck he already built. He's polite, sympathetic, and wrong, and the two staff below you softened the no enough that he kept climbing. Your letter must end the climb without ending his dignity.","task":"Write the letter's 3 sentences: the final no, the reason, and the one real option.","tips":["Say it's final: 'this is the department's final decision' — those words close the loop kindly.","One sentence of reason grounded in the rule's purpose, not just its existence.","Name the one legitimate path (variance application) with its honest odds; false hope restarts the climb."],"focus":["clarity","structure"],"placeholder":"The setback requirement cannot be waived, and this is the department's final decision. The rule exists to"},
    {"id":"hard-gov-senior-17","level":"senior","profession":"publicservice","title":"Telling the briefer his briefings fail","scenario":"Your policy director is brilliant and cannot brief: twenty minutes of context before any point, and the deputy minister has started routing around him. He doesn't know that yet. Telling him is a hard message about a fixable skill — and not telling him is how careers quietly end.","task":"Write your spoken 3-sentence opening for the conversation.","tips":["Name the behavior and the consequence he can't see: the deputy is routing around him.","Keep it about the skill, not the intellect — his analysis is the reason this is worth fixing.","End with the concrete fix and an offer: answer-first drills, your coaching, next briefing together."],"focus":["precision","audience"]},
    {"id":"hard-gov-senior-18","level":"senior","profession":"publicservice","title":"The contamination next door","scenario":"Soil testing at the old works yard found contamination migrating toward eleven residential properties. Homeowners must hear it from you before they read it — and the notice has to be honest about uncertainty without either false alarm or false comfort.","task":"Write the resident notice's first 3 sentences.","tips":["What was found, where, and what it means for them — before any process language.","Be exact about uncertainty: what testing shows, what it doesn't yet, when they'll know more.","Their next question is health and property value; answer the health one now, with the toxicologist's actual guidance."],"focus":["clarity","precision"],"placeholder":"Soil testing at the former works yard found solvent contamination that may extend beneath eleven properties on your street, including"},
    {"id":"hard-gov-senior-19","level":"senior","profession":"publicservice","title":"The target that can't be hit","scenario":"The premier's office set a 50% wait-time reduction target for your sector. Your analysis says 30% is the ceiling of possible. Telling the centre their number is wrong is career-adjacent risk; letting the government announce an impossible number is worse. Your note must be unimpeachable and unmistakable.","task":"Write the note's 3 opening sentences.","tips":["The conclusion first: 50% is not achievable in the timeframe; 30% is, at the stated funding.","Show the binding constraint in one sentence — the workforce math nobody can wish away.","Offer the constructive frame: what 50% WOULD require, costed, so the choice is theirs and informed."],"focus":["precision","structure"],"placeholder":"A 50% wait-time reduction is not achievable within the mandate window; 30% is, at current funding. The binding constraint is"},
    {"id":"hard-gov-senior-20","level":"senior","profession":"publicservice","title":"The disciplinary meeting's first minute","scenario":"An inspector skipped required site visits and logged them as complete. The disciplinary meeting is scheduled, the union rep will be present, and your opening must be specific, procedurally clean, and free of both anger and apology. What you say first sets whether this stays factual or becomes war.","task":"Draft your spoken opening 3 sentences.","tips":["State the specific findings with dates — allegations by record, not by character.","Name the meeting's purpose and process plainly: his opportunity to respond, the possible outcomes.","Strip every emotional adjective; the flattest accurate sentence is the strongest one in the room."],"focus":["precision","structure"]},
    {"id":"hard-gov-senior-21","level":"senior","profession":"publicservice","title":"The fee increase, unburied","scenario":"Transit fares rise 8% in January — the first increase in six years, and still the part everyone will hate. The draft release leads with three paragraphs of service improvements and mentions the increase in paragraph four. Every reporter will find it in nine seconds and write 'city buries fare hike.'","task":"Rewrite the release's first 2 sentences with the increase first.","tips":["The increase, the amount in real terms (25 cents), and the date — sentence one.","The context earns sentence two: first increase in six years, what it funds.","Burying bad news doesn't hide it; it just adds 'buried' to the story."],"focus":["clarity","audience"],"placeholder":"Transit fares will rise 25 cents to $3.50 on January 1 — the first increase in six years. The added revenue funds"},
    {"id":"hard-gov-senior-22","level":"senior","profession":"publicservice","title":"Leaving the partnership","scenario":"After four years, you're pulling your department out of the tri-agency outreach program — it duplicates your new in-house team. The partner agencies' directors are colleagues you'll work with for decades, and they'll hear this as abandonment unless the message is early, direct, and generous on transition.","task":"Write the 3-sentence message to the partner directors.","tips":["The decision and its date first, framed as decided — a 'consultation' about a done deal poisons the relationship worse than clarity.","One honest sentence of reason; they deserve the real one.","Be concrete about transition generosity: funding through the fiscal year, joint communication, client handover."],"focus":["clarity","audience"],"placeholder":"We will withdraw from the tri-agency outreach program effective March 31. Our new in-house team now covers the same"},
    {"id":"hard-gov-senior-23","level":"senior","profession":"publicservice","title":"Ordering the review of your own house","scenario":"After the records scandal, you're announcing an independent review of your own department — terms of reference you wrote, reviewing decisions you made. The statement has to make the review's independence believable, which means saying the uncomfortable parts out loud, including that your decisions are in scope.","task":"Write the announcement's first 3 sentences.","tips":["Announce the review and its scope in one sentence — including 'decisions made at the director level and above.'","Name the reviewer's independence concretely: external, reports publicly, unredacted access.","Say the sentence a defensive director would never say: 'including my own decisions.' That sentence is the announcement."],"focus":["impact","clarity"],"placeholder":"I have ordered an independent review of the records management failures, covering all decisions at the director level and above — including my own."},
    {"id":"hard-gov-senior-24","level":"senior","profession":"publicservice","title":"Not this promotion","scenario":"Your most loyal branch head applied for the ADM role and didn't get it — the panel ranked an external candidate first, and the panel was right. He finds out today, from you. He'll accept the outcome or start job-hunting based largely on whether the conversation is honest or managed.","task":"Draft your spoken 3 sentences: the outcome, the honest gap, and what's real about his future.","tips":["The decision first, without the compliment sandwich — he'll hear nothing else until it lands anyway.","Name the actual gap the panel saw, specifically enough to be actionable.","Offer only development you'll actually deliver; a consolation prize you forget about converts loyalty to exit."],"focus":["audience","precision"]},
    {"id":"hard-gov-senior-25","level":"senior","profession":"publicservice","title":"Telling the volunteers it's over","scenario":"The trail-stewardship program is ending — insurance costs tripled, and the department can't carry it. The two hundred volunteers who built those trails over fifteen years aren't staff or vendors; they gave the city their Saturdays. The message must be as honest as any hard message, and warmer than most.","task":"Write the message's first 3 sentences.","tips":["The ending and its date first, gently phrased but unmistakable.","The real reason, with the number — volunteers can handle the truth; they can't handle vagueness about their life's work.","Honor the specific legacy: kilometres built, and what of it the city commits to maintain. That commitment is the respect."],"focus":["audience","impact"],"placeholder":"The trail stewardship program will end on December 31. Our insurer has tripled the premium for volunteer field work, and"}
  ],
  "putting-it-together": [
    {"id":"together-gov-senior-01","level":"senior","profession":"publicservice","title":"One page to the minister, tonight","scenario":"A watermain failure has closed the hospital's main access road, the story is leading the evening news, and the minister's office wants one page by 8 p.m. Everything you've trained collapses into this: BLUF, precise numbers, owned judgment, next decision flagged — under 300 words.","task":"Write the note's opening 4 sentences: situation, action, risk, and the decision you need from her.","tips":["Sentence one carries the whole picture: what failed, who's affected, when access is restored.","Facts get numbers; judgments get 'I assess'; both get separated.","Flag the one decision that's hers, framed with your recommendation."],"focus":["structure","concision"],"placeholder":"A 400mm watermain failed at 2 p.m., closing Fairview Avenue — the hospital's main access — until approximately noon tomorrow."},
    {"id":"together-gov-senior-02","level":"senior","profession":"publicservice","title":"The 7 a.m. scrum, all skills live","scenario":"Overnight, a snowplow struck a parked ambulance; no injuries, but the video is everywhere. At 7 a.m. you walk into the scrum with no notes and every skill you have: the direct answer, the precise fact, the owned accountability, the calm close.","task":"Draft your spoken opening statement — 4 sentences before the first question.","tips":["Lead with the human fact: no one was hurt. Then what happened, in plain sequence.","Own the investigation and its date before anyone asks who's accountable.","End your statement with a period, not a trail-off — then take questions on your feet."],"focus":["clarity","impact"]},
    {"id":"together-gov-senior-03","level":"senior","profession":"publicservice","title":"Three audiences, one closure","scenario":"The Elm Street bridge closes Monday for emergency repairs. Same fact, three messages: a directive to staff, a briefing line for council, a notice to residents. Each audience needs a different lead, register, and level of detail — and all three must agree exactly on the facts.","task":"Write the first 2 sentences of each version.","tips":["Staff need actions and assignments; council needs cost and duration; residents need detours and dates.","The numbers must match across all three — mismatches become the story.","Write the resident version at grade-8 reading level; write council's with the dollar figure first."],"focus":["audience","structure"],"placeholder":"To staff: Elm Street bridge closes 6 a.m. Monday; crews A and C shift to the detour plan attached. To council:"},
    {"id":"together-gov-senior-04","level":"senior","profession":"publicservice","title":"The self-edit pass","scenario":"Your draft memo on the fleet-replacement deferral is due in an hour. Before sending, you run the full rubric against it: is the point first, is every claim numbered, is the ownership clear, is anything cushioned, can a third be cut? The discipline is running the checklist when you're tired.","task":"Write the 5-question checklist you'd run, then apply it: rewrite one weak sentence from your imagined draft.","tips":["The checklist earns its keep on deadline days, not easy ones.","Read the memo as its busiest reader: what do they know by the end of line one?","Your best edit is usually deletion; find the paragraph that exists to comfort you, not inform them."],"focus":["structure","concision"],"placeholder":"1. Is the recommendation in sentence one? 2. Does every claim carry its number?"},
    {"id":"together-gov-senior-05","level":"senior","profession":"publicservice","title":"The budget defense, first ninety seconds","scenario":"Committee, cameras, and a 9% increase to defend. Your opening ninety seconds must do it all: the ask up front, the roadmap, the strongest number, the owned recommendation — delivered like someone who has decided, to a room deciding whether to trust you.","task":"Write the spoken opening — 4 sentences.","tips":["The ask and its headline justification in sentence one.","Roadmap in sentence two: the three things you'll cover.","Close the opening with the sentence you want quoted; write it last, say it early."],"focus":["structure","impact"],"placeholder":"I'm requesting $84M — a 9% increase — and the entire increase is driven by three contracts this committee has already seen."},
    {"id":"together-gov-senior-06","level":"senior","profession":"publicservice","title":"Town hall: open, then pivot","scenario":"Tonight's town hall on the landfill expansion needs two skills in sequence: a two-minute opening that frames honestly and holds the room, then the pivot into Q&A that sets rules without sounding defensive. Most officials lose the meeting in the seam between the two.","task":"Write your opening 3 sentences plus the one-sentence Q&A pivot.","tips":["Open with the decision status and what tonight actually influences — inflated influence claims poison everything after.","Frame the trade-off honestly in one sentence; the room already knows there is one.","The pivot sets the contract: how long, what order, and your commitment to direct answers."],"focus":["audience","structure"]},
    {"id":"together-gov-senior-07","level":"senior","profession":"publicservice","title":"The binder's first page","scenario":"You're leaving the post, and your successor gets a transition binder. Page one is yours to write: the state of the department in one page — what's strong, what's fragile, what will bite them in month one. Everything you know about clarity, precision, and hard messages, for an audience of one.","task":"Write page one's first 4 sentences.","tips":["Lead with the thing that will bite first, with its date — the binder is a warning system, not a legacy statement.","Be precise about the fragile things: the two contracts, the one grievance, the aging system, by name.","Write with the candor you wish you'd received; flattery in a transition binder is sabotage."],"focus":["clarity","precision"],"placeholder":"Three things will reach your desk before you're ready: the union contract expires March 31, the radio system"},
    {"id":"together-gov-senior-08","level":"senior","profession":"publicservice","title":"Five minutes at the standing committee","scenario":"The legislative committee gives you five minutes on the housing file. Written testimony is tabled; the spoken five minutes is theatre with rules — the direct open, three signposted points, one number per point, the ask, and a close that ends on your position instead of evaporating.","task":"Write the full skeleton: opening sentence, three one-line points, closing sentence.","tips":["One number per point — the second number displaces the first in memory.","Signpost aloud: 'first, second, third' is how a transcript stays organized.","Rehearse the close until it's automatic; endings decay first under pressure."],"focus":["structure","concision"],"placeholder":"I have three points and one request. First: approvals now take 90 days;"},
    {"id":"together-gov-senior-09","level":"senior","profession":"publicservice","title":"Write the actual alert","scenario":"Flash flooding is expected within two hours in the riverside zones. You're approving the emergency alert text — 90 characters for the push notification, 280 for the full message. Every skill compresses to this: exactly what, exactly who, exactly what to do, zero ambiguity, zero panic.","task":"Write both: the 90-character push and the 280-character full alert.","tips":["Action verb first: 'Move to higher ground' beats 'Flooding is expected.'","Name the zones by the names residents use, not the emergency-plan codes.","Cut every word that isn't instruction, location, or time — adjectives cost lives-worth of attention."],"focus":["concision","clarity"],"placeholder":"FLASH FLOOD 2HR: Riverside & Milldale — move vehicles and people above Bank St now. Info: city.ca/flood"},
    {"id":"together-gov-senior-10","level":"senior","profession":"publicservice","title":"The annual report letter","scenario":"The director's letter opening the annual report is usually skipped by everyone — because it's usually a victory lap in the passive voice. Yours can be the exception: the year's one headline, the honest miss, the next year's stake in the ground. One page that a councilmember actually quotes.","task":"Write the letter's first 4 sentences.","tips":["Lead with the year's single most consequential fact, not a welcome.","Include the miss, unprompted, with its number — one honest paragraph buys the credibility for everything else.","End the opening looking forward with one dated commitment, not a mission statement."],"focus":["impact","precision"],"placeholder":"This year the department cut permit wait times from 90 days to 41 — and missed its inspection target for the second"},
    {"id":"together-gov-senior-11","level":"senior","profession":"publicservice","title":"From engineer's report to door-knocker","scenario":"The consultant's slope-stability report says 'factor of safety below 1.3 under seismic loading conditions.' Forty households above the escarpment need a notice they can read at their kitchen table. The register shift — technical to plain, without losing accuracy — is the whole assignment.","task":"Translate the finding into the notice's first 2 sentences.","tips":["Plain words, true content: what could happen, how likely, what changes for them now.","Don't round 'below standard' up to 'dangerous' or down to 'routine' — calibration survives translation.","The kitchen-table test: could a worried 70-year-old read this once and know what to do?"],"focus":["audience","precision"],"placeholder":"An engineering study found the slope behind your street is less stable than current standards require. Your home is safe to live in today, but"},
    {"id":"together-gov-senior-12","level":"senior","profession":"publicservice","title":"Rescuing the email thread","scenario":"Fourteen emails deep, three departments are arguing about who owns the encampment response, and the thread now contains two contradictory 'decisions.' You're the senior person on it. One message can end the thread: state the facts, name the decision, assign the actions, close the loop.","task":"Write the thread-ending email — 4 sentences.","tips":["Open by killing the ambiguity: 'To close this thread, here is where we've landed.'","One sentence per decision, one owner per action, dates on everything.","Change the subject line to 'DECISION:' — the thread's chaos was partly its label."],"focus":["structure","clarity"],"placeholder":"To close this thread: outreach leads the encampment response, effective today. Parks provides site access by Friday;"},
    {"id":"together-gov-senior-13","level":"senior","profession":"publicservice","title":"Ten minutes cut to three, at the podium","scenario":"You're at the conference podium when the organizer signals: the session is running long, please take three minutes, not ten. Your slides are useless now. What you keep is a live editing decision — the one story, the one number, the one takeaway — made while already speaking.","task":"Write the 3-minute spoken version's skeleton: opening line, the one story, the one number, the close.","tips":["Cut sections, not sentences — three compressed points is worse than one whole one.","Keep the story; stories survive compression better than frameworks.","Tell the room what you're doing: 'We're short on time, so here's the one thing.' Grace under cuts is presence."],"focus":["concision","impact"]},
    {"id":"together-gov-senior-14","level":"senior","profession":"publicservice","title":"The all-staff after the brutal week","scenario":"The audit dropped Monday, the layoff rumours started Wednesday, and by Friday the department's Slack is a grief channel. Your all-staff message must do several things at once: tell the truth, kill the false rumours specifically, own the real problems, and give people one solid thing to stand on.","task":"Write the message's first 4 sentences.","tips":["Address the worst rumour first, by name — vague reassurance confirms fears.","Separate cleanly: what's true, what's false, what's undecided (with the decision date).","End the opening with the one thing that is certain and good; people can carry one solid thing through uncertainty."],"focus":["audience","clarity"],"placeholder":"Let me deal with the rumour directly: there is no layoff list. Here is what is true:"},
    {"id":"together-gov-senior-15","level":"senior","profession":"publicservice","title":"The pair: statement and staff memo","scenario":"The department is being reorganized under a new deputy — public statement at noon, staff memo at 11:55. Same facts, two registers, zero contradictions: the public version leads with service continuity; the staff version leads with what happens to jobs. If the two diverge on substance, staff will trust neither.","task":"Write the first 2 sentences of each.","tips":["Draft the staff version first; the public version is its subset, not its spin.","The staff memo answers 'my job?' in sentence one or loses the reader to speculation.","Any fact in one must survive being read next to the other — assume both leak within the hour."],"focus":["audience","precision"],"placeholder":"To staff: The department moves under the new Community Services division on July 1 — no positions are eliminated"},
    {"id":"together-gov-senior-16","level":"senior","profession":"publicservice","title":"Cut one thing to fund another","scenario":"Your report asks council to close the underused Eastside counter to fund the mobile service unit. It's a hard message and a persuasion case fused: the closure must be owned plainly, and the trade must be framed as one decision, not a cut with a consolation prize stapled on.","task":"Write the report's opening 3 sentences.","tips":["Present it as one motion: close X to fund Y — splitting them lets council take the fund and refuse the cut.","The closure gets its honest numbers; the new service gets its concrete reach. Same precision for both halves.","Name who loses and who gains, specifically; a trade with hidden losers gets unwound at the meeting."],"focus":["structure","impact"],"placeholder":"I recommend closing the Eastside counter — 30 visits a day, $410K a year — to fund a mobile unit that will reach"},
    {"id":"together-gov-senior-17","level":"senior","profession":"publicservice","title":"The wings-side brief","scenario":"The mayor is thirty seconds from walking onstage to announce the housing accord, and she turns to you: 'Anything change overnight?' One thing did — a partner agency is wobbling on its commitment. The brief must be complete, calm, and actionable, delivered in the time it takes to walk to a podium.","task":"Write the spoken 2-sentence brief.","tips":["Lead with the delta and its size: what changed, how much it matters to the next ten minutes.","Give her the adjusted line: what she can still say safely, verbatim.","No background, no hedging, no 'we should discuss' — the podium is the deadline."],"focus":["concision","audience"]},
    {"id":"together-gov-senior-18","level":"senior","profession":"publicservice","title":"One slide for cabinet","scenario":"Your submission goes to cabinet committee, and the deputy tells you: one slide. The wastewater program — $60M, four years, three communities — must become one slide that a minister can absorb in ninety seconds and defend in a scrum an hour later.","task":"Write the slide: headline, three bullets, and the footer line.","tips":["The headline is the decision, not the topic: 'Approve $60M to end sewage bypasses in three communities by 2029.'","Each bullet is one number plus its meaning — no bullet needs a sub-bullet.","The footer answers the scrum question: cost per household, or the consequence of not acting."],"focus":["concision","structure"],"placeholder":"HEADLINE: Approve $60M over four years to end sewage bypasses in three communities by 2029."},
    {"id":"together-gov-senior-19","level":"senior","profession":"publicservice","title":"Four minutes of live radio","scenario":"The morning show has you for four minutes on the property tax increase. Live radio compresses everything: the direct answer under pressure, the one precise number, the resident-first framing, the bridge back when the host chases a tangent. No notes survive contact with a good host.","task":"Draft your answer to the opening question — 'Why should anyone pay 6% more?' — in 3 spoken sentences.","tips":["Answer the actual question first: what residents get for the 6%, in kitchen-table terms.","One number, repeated once — radio listeners keep a single figure at best.","Practice the bridge phrase for tangents: answer briefly, return to your message, without the robotic 'what I can tell you is.'"],"focus":["audience","impact"]},
    {"id":"together-gov-senior-20","level":"senior","profession":"publicservice","title":"The apology with all four parts","scenario":"The benefits system failure left 3,000 families unpaid for three weeks. The public apology must integrate everything: the plain ownership, the precise facts, the concrete remedy with dates, and the structural fix — in under 150 words, because contrition padded is contrition doubted.","task":"Write the full apology statement — 4-5 sentences.","tips":["Part one: what we did, active voice, with the numbers. Part two: sorry, said plainly, once.","Part three: the remedy every affected family gets, with its date. Part four: what changes so it can't recur.","No 'we take this seriously,' no 'journey,' no 'committed to excellence' — the four parts, then stop."],"focus":["clarity","impact"],"placeholder":"We failed to pay 3,000 families their benefits for three weeks. I am sorry — plainly and without qualification."},
    {"id":"together-gov-senior-21","level":"senior","profession":"publicservice","title":"Two hours of cross-examination","scenario":"The public accounts committee has your department's file and two hours. This is the integration exam: signposted answers, precise concessions, corrections made in real time, 'I don't know' said cleanly, and the same composed voice in minute 110 as in minute 5. Endurance is a communication skill.","task":"Write your 3 anchor formulations: your core position in one sentence, your concession sentence, and your 'don't know' sentence.","tips":["Prepare the three sentences you'll return to; under fatigue you fall to your preparation, not your talent.","Concede the true criticisms early and precisely — it buys the standing to contest the false ones.","Watch your own tempo in hour two; rushed answers late in a hearing are where the misstatements live."],"focus":["structure","precision"],"placeholder":"Core: The program met 9 of 11 targets, and I own the two misses. Concession: On procurement documentation, the auditor is right."},
    {"id":"together-gov-senior-22","level":"senior","profession":"publicservice","title":"Written for both readers","scenario":"Your memo recommending against the sole-source contract will be read by the deputy minister today and, quite possibly, by a legislative committee in two years. Two audiences, one text: candid enough to serve the decision now, precise and fair enough to stand in public later.","task":"Write the memo's opening 3 sentences with both readers in mind.","tips":["Candor and defensibility converge on the same style: precise claims, sourced facts, labeled judgments.","Write nothing about the vendor you couldn't say at a hearing — characterize conduct, never character.","The two-reader test isn't self-censorship; it's the discipline that makes advice durable."],"focus":["precision","audience"],"placeholder":"I recommend against sole-sourcing this contract. The exemption criteria are not met: two qualified vendors responded to"},
    {"id":"together-gov-senior-23","level":"senior","profession":"publicservice","title":"Your last message to the department","scenario":"After nine years, you're leaving, and the farewell message to 600 staff is the final thing they'll read from you. The genre invites every sin: length, sentiment, self-reference. The discipline you've preached — brevity, specificity, audience-first — is now the tribute itself.","task":"Write the farewell — 4 sentences, complete.","tips":["Make it about them: name the two or three real things the department did, with their numbers.","One sentence of genuine feeling beats four of it; specificity is how feeling reads as true.","End facing forward — their next chapter, not your reflection. Then actually stop."],"focus":["concision","audience"],"placeholder":"Nine years ago this department took 90 days to answer a resident; today it takes 12. You did that —"},
    {"id":"together-gov-senior-24","level":"senior","profession":"publicservice","title":"First message to a bruised department","scenario":"You arrive as the new director of a department that's been through two years of scandal coverage and three leaders. Your first message — spoken at all-staff, then sent in writing — must integrate honesty about the past, presence about the future, and one immediate, checkable commitment.","task":"Draft the spoken opening 4 sentences.","tips":["Name the hard history in one plain sentence; pretending it away tells staff you'll pretend other things too.","Make one specific commitment with a date inside your first month — trust rebuilds on kept small promises, not speeches.","Sound decided about how you'll lead, humble about what you don't yet know — and label which is which."],"focus":["audience","impact"]},
    {"id":"together-gov-senior-25","level":"senior","profession":"publicservice","title":"Three minutes to win the vote","scenario":"The capstone: council votes tonight on the service-modernization plan you've built for two years, and you have three minutes at the microphone before the vote. BLUF, one number, one resident, the strongest objection answered, the owned recommendation, the ask. Everything, in order, out loud.","task":"Write the full 3-minute address — 6-7 sentences.","tips":["Open with the decision and close with the ask; the middle is one story and one number, not five.","Answer the strongest objection by name — the swing vote is listening for whether you've heard them.","The last sentence is the vote: say exactly what you're asking council to do, and stop talking."],"focus":["structure","impact"],"placeholder":"Tonight's decision is simple to state: approve the plan that takes a resident's wait from 90 days to 30. Last March, Mrs."}
  ]
};
